/* =============================================================
   bible-timeline.js — Visual Bible Timeline data (F4-D, expanded)

   ~90 events from Creation to Revelation, ordered chronologically.
   Era IDs match the Bible Lands period overlays so events visually
   thread through the same color system as the map. The 'judges'
   era is unique to the timeline; 'second-temple' covers the
   intertestamental period.

   Years use BC negative / AD positive integer convention internally
   (year property), with displayYear for the rendered label. Pre-
   historical events get displayYear strings like "Beginning" or
   "~2400 BC".
============================================================= */

const BIBLE_TIMELINE_EVENTS = [
  // ── ACT 1: CREATION & PRE-HISTORY ─────────────────────────
  { id:'creation', year:-9999, displayYear:'Beginning', era:'patriarchs',
    icon:'🌌', title:'Creation',
    subtitle:'God speaks the universe into being.',
    body:`<p>"In the beginning, God created the heavens and the earth." Light from darkness. Water from sky. Land from sea. Plants from soil. Lights in the firmament. Fish in the deep, birds in the air, beasts on the ground. Each day God speaks, and the universe answers. He does not assemble matter — He calls things into being from nothing at all.</p><p>On the sixth day He stoops. From the dust He fashions a man, breathes His own breath into the nostrils, and image is born. Male and female are made in the likeness of the Trinity itself — designed for relationship, given dominion, blessed with work. The seventh day is set aside not from fatigue but from completion: the universe has its King, the King has His house, and rest enters time.</p><p>Every page that follows hangs from this opening. There is a Maker. There is a meaning. Matter is not eternal, evil is not necessary, and we are not accidents. The Bible begins with a wedding of heaven and earth — and the long story of Scripture is the rescue of that wedding after we ourselves break it.</p>`,
    whyMatters:`<p>You are not a cosmic mistake. The body in the mirror, the soul behind it, the day in front of you — all of it begins as gift, called into being by a Maker who delights in His work. To remember Creation is to remember that you were wanted before you were anything else.</p>`,
    keyVerse:{ ref:'Genesis 1:1', text:'In the beginning, God created the heavens and the earth.' },
    scriptureRefs:['Genesis 1','Genesis 2'], relatedStoryId:'creation' },
  { id:'fall', year:-9998, displayYear:'Eden', era:'patriarchs',
    icon:'🍎', title:'The Fall',
    subtitle:'Humanity chooses independence from God.',
    body:`<p>The garden is finished. The man and the woman walk with God in the cool of the day. One tree is forbidden — not because the fruit is poison, but because love requires a real choice. The serpent appears: subtle, smooth, twisting God's words by a single syllable. "Did God really say?" Doubt is planted before disobedience. Eve looks. The fruit is taken. Adam, standing silent beside her, eats too.</p><p>Eyes open. Shame arrives like a stranger they cannot turn away. They sew fig leaves; they hide in the bushes; they hear footsteps and run. God comes asking the saddest question in the Bible: "Where are you?" Curses fall on the serpent, on childbirth, on labor, on the ground itself. But within the curse, the first promise glimmers — a future Seed of the woman who will crush the serpent's head.</p><p>Eden's gate closes behind them. Cherubim with a flaming sword guard the way to the tree of life. Every aching thing about being human starts here — death, distance, distortion of every good gift. Yet every page after this is God walking toward us again, this time wearing skin.</p>`,
    whyMatters:`<p>The Fall explains why nothing in the world quite fits — including yourself. The longing for a goodness you can't manufacture, the failures that shock even you, the ache for home — these aren't proof you are broken beyond repair. They are proof you remember Eden, and the Gardener is coming back.</p>`,
    keyVerse:{ ref:'Genesis 3:15', text:'I will put enmity between you and the woman, and between your offspring and her offspring; he shall bruise your head, and you shall bruise his heel.' },
    scriptureRefs:['Genesis 3','Romans 5:12'], relatedStoryId:'the-fall' },
  { id:'flood', year:-2400, displayYear:'~2400 BC', era:'patriarchs',
    icon:'🌊', title:'The Flood',
    subtitle:'God resets through one faithful family.',
    body:`<p>Generations pass. By Noah's time, "every intention of the thoughts of the heart was only evil continually." God grieves that He made humanity. But Noah finds favor — one righteous man in a violent world — and God tells him to build a boat in the shape of a long wooden box, three hundred cubits by fifty by thirty, on dry land, hundreds of miles from any sea.</p><p>For decades Noah builds and warns. Neighbors mock. Skies stay clear. Then the springs of the deep burst open and the windows of heaven are thrown wide. Forty days and nights the water rises until the highest mountains disappear. Inside the ark: one family, two of every kind of creature, and a God who shut the door Himself. When the water finally falls, a raven goes out and does not return; a dove brings back an olive leaf.</p><p>Noah builds an altar on a new earth. The rainbow becomes the first sign attached to the first covenant — God promises never again to flood the world. The flood is not just punishment; it is reset, judgment and grace folded into the same rising water. Peter would later see the ark as a picture of baptism: salvation through judgment, on the other side of death.</p>`,
    whyMatters:`<p>The flood is uncomfortable because it tells the truth about evil — that God will not look the other way forever. And yet the same God who closes the sky also builds the boat. Wherever His judgment falls, His mercy has already gone ahead, hammering wood, opening a door.</p>`,
    keyVerse:{ ref:'Genesis 9:13', text:'I have set my bow in the cloud, and it shall be a sign of the covenant between me and the earth.' },
    scriptureRefs:['Genesis 6-9','2 Peter 2:5'], relatedStoryId:'noahs-ark' },
  { id:'babel', year:-2300, displayYear:'~2300 BC', era:'patriarchs',
    icon:'🗼', title:'Tower of Babel',
    subtitle:'Pride scatters humanity.',
    body:`<p>The descendants of Noah were told to fill the earth. Instead, they settle on a plain in Shinar and decide to stay together. They invent baked brick and bitumen. They lay out a city with a tower at the center "with its top in the heavens, that we may make a name for ourselves, lest we be dispersed."</p><p>The story is told tongue-in-cheek. God has to "come down" to see the tower humanity thinks is reaching Him. Pride is not stronger than mortar; it is also more dangerous. God responds with confusion — not punishment so much as kindness, splintering one language into many so that unified human ambition cannot do unlimited human damage. The city is left half-built. The people scatter into nations.</p><p>Every later confusion between peoples traces back here. So does the great reversal at Pentecost: tongues of fire on the heads of disciples, and suddenly Parthians, Medes, Elamites, and Romans all hear the gospel in their own dialect. What pride scattered, the Spirit gathers — not by erasing differences, but by making them sing the same song.</p>`,
    whyMatters:`<p>Every age has its tower. Every soul has its name to make. The Babel pattern lives in any project — including the spiritual ones — that uses God's gifts to climb past needing God Himself. The cure isn't smaller dreams; it's a Maker worth being known by.</p>`,
    keyVerse:{ ref:'Genesis 11:4', text:'Come, let us build ourselves a city and a tower with its top in the heavens, and let us make a name for ourselves.' },
    scriptureRefs:['Genesis 11:1-9'], relatedStoryId:'tower-babel' },

  // ── ACT 2: PATRIARCHS ─────────────────────────────────────
  { id:'abraham', year:-2000, displayYear:'~2000 BC', era:'patriarchs',
    icon:'⭐', title:"Abraham's Call",
    subtitle:'God promises a great nation through one man.',
    body:`<p>Centuries after Babel, in the city of Ur on the Euphrates, God speaks to a seventy-five-year-old man named Abram. No backstory of righteousness is given. No reason for the choice is offered. The call is simply: "Go from your country and your kindred and your father's house to the land that I will show you. And I will make of you a great nation, and I will bless you and make your name great, so that you will be a blessing."</p><p>The promise has three layers — a land, a people, and a blessing for all nations. Each is impossible: Abram has no son, his wife is barren, and the destination is unnamed. He goes anyway. The narrowing has begun. God will work through one family so the blessing can later widen to all the families of the earth. Through this old man and his eventual son will come the line of Isaac, Jacob, David, and finally Jesus.</p><p>Hebrews remembers him as the great example of faith: "By faith Abraham obeyed when he was called to go out to a place that he was to receive as an inheritance, and he went out, not knowing where he was going." Faith does not mean having a map. It means trusting the One who has one.</p>`,
    whyMatters:`<p>God still calls people who don't qualify. He still asks them to leave something they can see for something they can't. The blessings He hands out come with a wider purpose — through you, to others. The story you're part of is bigger than your story.</p>`,
    keyVerse:{ ref:'Genesis 12:2-3', text:'I will make of you a great nation, and I will bless you and make your name great, so that you will be a blessing... and in you all the families of the earth shall be blessed.' },
    scriptureRefs:['Genesis 12:1-3','Hebrews 11:8'], relatedSiteId:'shechem', relatedStoryId:'abrahams-covenant' },
  { id:'sodom', year:-1950, displayYear:'~1950 BC', era:'patriarchs',
    icon:'🔥', title:'Sodom & Gomorrah',
    subtitle:'Judgment falls; Abraham intercedes.',
    body:`<p>The cities of the plain — Sodom and Gomorrah and three others — have become bywords for cruelty. The outcry against them reaches heaven. God comes down to see; three travelers visit Abraham's tent on the way. After lunch under the oaks of Mamre, two of them turn toward the cities. The third stays to talk with Abraham.</p><p>What follows is one of Scripture's strangest and most tender scenes — a man bargaining with God over how many righteous people would be enough to save a city. Fifty? Forty-five? Forty? Thirty? Twenty? Ten? At every step God yields. Abraham learns something about the heart of the Judge: He is not eager to destroy; He is eager to spare. Ten righteous are not found. Lot and his daughters barely escape, his wife looks back and turns to salt, and fire rains down at sunrise.</p><p>Sodom is not destroyed for its inhospitality alone or its sexual sin alone; Ezekiel later names pride, gluttony, and a refusal to help the poor as core to its rot. The story is harder than slogans. Justice falls; mercy is offered first; intercession is heard. The God who would later let His own city walk past Him to a cross has always been negotiated with by anyone willing to ask.</p>`,
    whyMatters:`<p>If you have ever wondered whether God hears the cries of the abused or the prayers of the few, this story answers: yes. Justice is real; mercy is real; intercession is real. There is no city beyond rescue while there are still people willing to pray for it.</p>`,
    keyVerse:{ ref:'Genesis 18:25', text:'Shall not the Judge of all the earth do what is just?' },
    scriptureRefs:['Genesis 18:16-33','Genesis 19'] },
  { id:'isaac-binding', year:-1900, displayYear:'~1900 BC', era:'patriarchs',
    icon:'🐏', title:'The Binding of Isaac',
    subtitle:'God provides the substitute on Moriah.',
    body:`<p>Isaac is the long-awaited son — born when Abraham is a hundred and Sarah is ninety, laughed about by everyone including her, the living evidence that nothing is too hard for the Lord. Then comes the test no parent could imagine. "Take your son, your only son Isaac, whom you love, and go to the land of Moriah, and offer him there as a burnt offering on one of the mountains of which I shall tell you."</p><p>Three silent days of walking. At the foot of the mountain Abraham leaves the servants — "We will worship and come again to you." (We. Both of us. He already trusts that God can raise the dead, Hebrews tells us.) On the mountain Isaac asks the unbearable question: "Where is the lamb?" Abraham answers, "God will provide the lamb, my son." Wood is laid; the boy is bound; the knife rises.</p><p>The angel of the Lord cries from heaven. A ram is caught by its horns in a thicket. The substitute is provided — not because God didn't mean it, but because He always meant to provide Himself. The mountain is Moriah — the same hill where Solomon would later build the Temple, and where the city of Jerusalem would eventually surround the place where another Father, two thousand years later, would offer His only Son and not stop the knife.</p>`,
    whyMatters:`<p>God will ask you to hold the things you love most with open hands. He is not cruel; He is teaching you that He is enough — and that whatever He requires, He will provide. On the mountain where Abraham was spared, Another would not be. That is how seriously God meant the lamb.</p>`,
    keyVerse:{ ref:'Genesis 22:14', text:'So Abraham called the name of that place, The LORD will provide; as it is said to this day, On the mount of the LORD it shall be provided.' },
    scriptureRefs:['Genesis 22','Hebrews 11:17-19'], relatedStoryId:'abraham-isaac' },
  { id:'jacob-ladder', year:-1850, displayYear:'~1850 BC', era:'patriarchs',
    icon:'🪜', title:"Jacob's Ladder",
    subtitle:'Heaven and earth meet at Bethel.',
    body:`<p>Jacob has just deceived his father, stolen his brother's blessing, and fled north with nothing but a staff. The first night on the run he sleeps in the open with a stone for a pillow — the kind of bed a guilty man earns. There, in the dirt, God meets him.</p><p>He dreams of a stairway reaching from earth to heaven with the angels of God ascending and descending on it. At the top stands the Lord Himself, who renews to Jacob every promise He gave to Abraham and Isaac — the land, the offspring, the blessing for all peoples, and one more line: "Behold, I am with you and will keep you wherever you go." Grace, before repentance. Promise, before performance.</p><p>Jacob wakes shaken. He sets up the stone as a pillar, pours oil on it, and names the place Bethel — "house of God." Centuries later, Jesus would tell Nathanael, "You will see heaven opened, and the angels of God ascending and descending on the Son of Man." The ladder was always a Person. Wherever Christ is, the gap between earth and heaven has been closed.</p>`,
    whyMatters:`<p>You can be running from God when He meets you. Bethel says you don't have to climb to heaven; heaven has already let down a stairway. The connection between you and God isn't built from the bottom up — it was built from the top down, in the shape of a cross.</p>`,
    keyVerse:{ ref:'Genesis 28:16', text:'Surely the LORD is in this place, and I did not know it.' },
    scriptureRefs:['Genesis 28:10-22','John 1:51'], relatedSiteId:'bethel', relatedStoryId:'jacob-esau' },
  { id:'jacob-wrestles', year:-1830, displayYear:'~1830 BC', era:'patriarchs',
    icon:'💪', title:'Jacob Wrestles God',
    subtitle:'A new name for a wounded man.',
    body:`<p>Twenty years later. Jacob has worked for his uncle Laban, married two sisters, fathered twelve children, and accumulated wealth. But he must finally face Esau — the brother he cheated, who is coming to meet him with four hundred men. Jacob sends gifts ahead. He divides his family for safety. Then, alone at the brook Jabbok at night, a man wrestles with him until daybreak.</p><p>It is not even a fair fight. The stranger could clearly end it at any moment; instead He waits. As dawn approaches He touches Jacob's hip and dislocates it with a touch. Even then Jacob refuses to let go: "I will not let you go unless you bless me." The blessing comes in the form of a new name. "Your name shall no longer be called Jacob — heel-grabber, supplanter — but Israel, for you have striven with God and with men, and have prevailed."</p><p>He limps away into the rising sun with a new name, a new identity, and a permanent reminder. Every patriarch in Scripture is bent before he is named. The same God who blesses you will first wound you in the place you would otherwise have used to fight Him. Israel — the whole nation, named after this night — is not a strong people. It is a limping people who have refused to let go.</p>`,
    whyMatters:`<p>The thing you wrestle with in the dark may turn out to be the One who is trying to bless you. Sometimes God's grip looks like a fight, and the limp He leaves behind is the proof you actually met Him. Don't let go before the blessing comes.</p>`,
    keyVerse:{ ref:'Genesis 32:26', text:'I will not let you go unless you bless me.' },
    scriptureRefs:['Genesis 32:22-32'] },
  { id:'joseph-egypt', year:-1700, displayYear:'~1700 BC', era:'patriarchs',
    icon:'👑', title:'Joseph in Egypt',
    subtitle:'God works evil into rescue.',
    body:`<p>Jacob's favorite son. Eleven brothers, one coat of many colors, two dreams of sheaves and stars bowing down to him. The family fault lines crack open. Joseph is thrown into a pit, then sold to a passing caravan, then resold to Potiphar, an officer of Pharaoh. He rises in Potiphar's house. Then Potiphar's wife lies about him and he is thrown into prison, forgotten there for years.</p><p>In prison he interprets two dreams — one for the cupbearer who is restored, one for the baker who is hanged. Two more years pass before Pharaoh dreams of seven fat cows and seven lean ones, seven full heads of grain and seven thin. Joseph is summoned, interprets, and the dungeon-boy stands before the most powerful man in the world by morning. He becomes second-in-command of Egypt, stockpiles grain through seven years of plenty, and feeds the known world through seven years of famine.</p><p>His brothers come down for bread, not recognizing the dignitary they bow to. After tests of their changed hearts, Joseph reveals himself in tears: "I am Joseph your brother, whom you sold into Egypt. And now do not be distressed... for God sent me before you to preserve life... You meant evil against me, but God meant it for good." The family of Israel survives, by way of an Egyptian palace, because a young man in a pit refused to stop trusting.</p>`,
    whyMatters:`<p>God writes long sentences. The pit and the prison were not detours from Joseph's calling — they were the road to it. If your present feels like waiting in a place no one remembers, you may be exactly where the story needs you to be. He will reveal Himself in His time.</p>`,
    keyVerse:{ ref:'Genesis 50:20', text:'As for you, you meant evil against me, but God meant it for good, to bring it about that many people should be kept alive, as they are today.' },
    scriptureRefs:['Genesis 37','Genesis 50:20'], relatedStoryId:'joseph' },

  // ── ACT 3: EXODUS & CONQUEST ──────────────────────────────
  { id:'burning-bush', year:-1447, displayYear:'~1447 BC', era:'exodus-conquest',
    icon:'🌿', title:'The Burning Bush',
    subtitle:'God names Himself: I AM.',
    body:`<p>Four hundred years of silence. Israel's family has grown into a nation of slaves in Egypt, groaning under brick quotas. Moses — once an Egyptian prince, then a murderer, now a fugitive — is eighty years old, herding his father-in-law's sheep on the back side of the wilderness. The dream of rescuing his people is decades dead.</p><p>A bush on Mount Horeb catches fire and does not burn down. Moses turns aside to see this strange sight — and out of the flame comes the voice that will reshape the next forty years of his life. "Take off your sandals, for the place where you are standing is holy ground." God names His grief over His people. He commissions Moses to go back to Egypt. Moses argues five times — Who am I? Who shall I say sent me? They won't believe me. I am slow of speech. Send someone else — and every time God answers.</p><p>The answer to "Who shall I say sent me?" is the most important name in Scripture: I AM WHO I AM. Not a god who came into being, not a god who depends on anyone else, not a god who could be otherwise. Pure being. Self-existent. The Sender does not need a sender. With that name burning in his memory, Moses turns back toward Egypt with his brother Aaron and a wooden staff.</p>`,
    whyMatters:`<p>God still meets people on the back side of the wilderness, where they thought their useful years were over. Holy ground is wherever He shows up — even at a bush no one else would have noticed. If you have argued with His call, you are in good company. The bush is still burning.</p>`,
    keyVerse:{ ref:'Exodus 3:14', text:'God said to Moses, I AM WHO I AM. And he said, Say this to the people of Israel, I AM has sent me to you.' },
    scriptureRefs:['Exodus 3','Exodus 4'], relatedStoryId:'burning-bush' },
  { id:'exodus', year:-1446, displayYear:'~1446 BC', era:'exodus-conquest',
    icon:'🔥', title:'The Exodus',
    subtitle:'God rescues Israel from Egypt.',
    body:`<p>Moses stands before Pharaoh with a wooden staff: "Let my people go, that they may serve me in the wilderness." Pharaoh sneers. Ten plagues follow, each one a direct strike at an Egyptian god — the Nile turned to blood (defeating Hapi), frogs (Heqet), flies, livestock, boils, hail, locusts, darkness over the land of the sun-god Ra. With every plague Pharaoh hardens, and Egypt is taken apart slowly.</p><p>The final plague is the Passover. Every household in Israel slaughters a lamb without blemish, paints the blood on the doorframes, eats the meat with bitter herbs and unleavened bread, ready to walk. At midnight the angel of death moves through Egypt; every firstborn son dies — Pharaoh's heir, the cattle's first calf, the prisoner's son — except where the blood marks the door. By dawn Pharaoh is screaming at Moses to leave.</p><p>Two million slaves march out, jewelry pressed into their hands by terrified neighbors. Pharaoh changes his mind and chases them with six hundred chariots. They are trapped at the Red Sea. Moses lifts his staff; the wind blows all night; the waters stand up in walls; Israel walks across on dry ground. When the Egyptians follow, the walls collapse. Miriam picks up a tambourine on the far shore and starts to sing. They will sing about this for three thousand years.</p>`,
    whyMatters:`<p>The Passover lamb still stands at the door. Every escape from death in Scripture rhymes with this night. The God who heard groaning in Egypt is still the God who hears it in your kitchen, your hospital room, your prison cell. He moves on schedule, not yours, but He moves.</p>`,
    keyVerse:{ ref:'Exodus 14:14', text:'The LORD will fight for you, and you have only to be silent.' },
    scriptureRefs:['Exodus 12','Exodus 14'], relatedStoryId:'plagues-red-sea' },
  { id:'sinai-law', year:-1446, displayYear:'~1446 BC', era:'exodus-conquest',
    icon:'📜', title:'The Law at Sinai',
    subtitle:'Rescued people receive their identity.',
    body:`<p>Three months out from Egypt the people camp in the wilderness of Sinai at the foot of a mountain. God tells Moses to consecrate the people for three days. On the morning of the third day, thunder and lightning crash, a thick cloud covers the mountain, a trumpet blast grows louder and louder, and the whole mountain trembles like a drumhead. The people stand at a distance, terrified.</p><p>Out of the cloud comes the Voice. Ten commandments — the first four about love for God, the last six about love for neighbor — written by the finger of God on tablets of stone. Around those ten, a whole code of justice unfolds: how to treat the foreigner, the widow, the slave, the enemy's lost ox. Israel will become a kingdom of priests, a holy nation, a people whose ordinary life is meant to display the character of their God to the world.</p><p>The Law was never the way to earn God's love — He had already rescued them from slavery before He gave them a single command. It was the shape of life with the God who had already saved them. Centuries later, Jesus would say He came not to abolish the Law but to fulfill it; Paul would say it was a tutor leading us to Christ. The mountain shakes here for a reason: a holy God has entered into covenant with a forgiven people.</p>`,
    whyMatters:`<p>Rescue comes first; rules come second. God doesn't hand you commandments so you can earn your way into His family. He's already pulled you out of Egypt. The Law is His way of saying, "Now here's how my children live free."</p>`,
    keyVerse:{ ref:'Exodus 20:2-3', text:'I am the LORD your God, who brought you out of the land of Egypt, out of the house of slavery. You shall have no other gods before me.' },
    scriptureRefs:['Exodus 19','Exodus 20'], relatedSiteId:'mt-sinai', relatedStoryId:'ten-commandments' },
  { id:'golden-calf', year:-1446, displayYear:'~1446 BC', era:'exodus-conquest',
    icon:'🐂', title:'The Golden Calf',
    subtitle:'Worship collapses while Moses is on the mountain.',
    body:`<p>Moses is on the mountain forty days receiving the Law. Down at the base, the people grow restless. He has been gone too long. The God of thunder feels far away. They go to Aaron — Moses' brother, the priest-in-training — and demand: "Make us gods who shall go before us." Aaron asks for their gold earrings. He melts them down and shapes a calf, builds an altar before it, and announces: "Tomorrow shall be a feast to the LORD."</p><p>The morning is a riot — sacrifice, eating, drinking, and the kind of celebration God specifically forbade. Moses comes down the mountain with the tablets in his hands. When he sees the calf and the dancing, he smashes the tablets at the foot of the mountain. He grinds the calf to powder, scatters it on the water, and makes the people drink. Three thousand fall that day. Moses goes back up the mountain alone and pleads — "If you will, forgive their sin; but if not, please blot me out of your book." God says no, He will not blot Moses out, but neither has He abandoned the people.</p><p>The golden calf is a warning that runs through the rest of Scripture: even right after rescue, even at the base of God's own mountain, the human heart cannot wait. We invent gods we can manage. The God who has just spoken from fire becomes a calf we can carry. The cost is high, but the covenant is not over. God will come down again — this time so close that no one will ever again confuse Him with metal.</p>`,
    whyMatters:`<p>The idol you make is always smaller than the God you're avoiding. When God feels slow, the temptation is to manufacture something visible. Wait for Him instead — He is coming down with the real thing, not a melted-gold copy.</p>`,
    keyVerse:{ ref:'Exodus 32:31-32', text:'Alas, this people has sinned a great sin. They have made for themselves gods of gold. But now, if you will forgive their sin — but if not, please blot me out of your book that you have written.' },
    scriptureRefs:['Exodus 32'] },
  { id:'tabernacle', year:-1445, displayYear:'~1445 BC', era:'exodus-conquest',
    icon:'⛺', title:'The Tabernacle Built',
    subtitle:'God dwells in the middle of His people.',
    body:`<p>God gives Moses detailed plans on the mountain — not for a city or an army, but for a tent. Acacia wood overlaid with gold. Curtains of blue and purple and scarlet linen. A bronze altar for sacrifice. A bronze basin for washing. A golden lampstand. A table of showbread. An altar of incense. And, in the innermost chamber behind a thick veil, the Ark of the Covenant — a gold-plated box holding the tablets of the Law, topped with two cherubim of beaten gold whose wings nearly touch.</p><p>For months the whole camp gives. Gold, silver, bronze, dyed yarn, ram skins, acacia poles, precious stones — given so freely that Moses eventually has to tell them to stop. The skilled craftsmen Bezalel and Oholiab work with a Spirit-given wisdom. On the first day of the first month of the second year, the tabernacle is finished. Moses sets it up, and the cloud descends, and the glory of the LORD fills the tent so thickly that even Moses cannot enter.</p><p>God is now living in the middle of His people. Not on a mountain at a distance, but in a tent at the center of the camp, moving with them wherever they go. Every detail of the tabernacle foreshadows something Christ will fulfill: the lamb, the bread, the light, the priest, the veil. John would later write of Jesus, "The Word became flesh and tabernacled among us" — using the exact word for this tent.</p>`,
    whyMatters:`<p>God's preferred address is not a palace; it is the middle of His people. Wherever the church gathers, wherever a believer prays, wherever a soul says yes — He pitches His tent. You do not have to climb a mountain to find Him. He has moved in.</p>`,
    keyVerse:{ ref:'Exodus 40:34', text:'Then the cloud covered the tent of meeting, and the glory of the LORD filled the tabernacle.' },
    scriptureRefs:['Exodus 25','Exodus 40:34-38'] },
  { id:'twelve-spies', year:-1445, displayYear:'~1445 BC', era:'exodus-conquest',
    icon:'🍇', title:'The Twelve Spies',
    subtitle:'Ten see giants. Two see God.',
    body:`<p>One year of camping at Sinai. Now Israel sits at the edge of the Promised Land — Kadesh-barnea, in the wilderness of Paran. God tells Moses to send twelve men, one from each tribe, to scout out the land. They go for forty days. They cut a single cluster of grapes so heavy two men carry it on a pole. They walk the cities and watch the people.</p><p>Ten come back terrified. "The land flows with milk and honey, but the people are stronger than we are. We saw giants there. We were like grasshoppers in our own sight, and so we were in theirs." Joshua and Caleb cut against the report: "Do not rebel against the LORD. Their protection is removed from them. The LORD is with us; do not fear them." The crowd picks the ten. They weep all night. They talk about choosing a new leader and going back to Egypt.</p><p>God's verdict is severe. The generation that just walked through the Red Sea will not enter the land. They will wander forty years — one for each day the spies were gone — until every adult unbeliever has died in the wilderness. Only Joshua and Caleb, and the children whom the parents feared could not survive, will inherit the promise. The cost of unbelief is never just a delay; it is sometimes an entire generation.</p>`,
    whyMatters:`<p>God shows you the land before He gives it to you. The question is what you'll do with the giants. Faith doesn't pretend the obstacles aren't real; it remembers Who is bigger than they are. Don't let fear write you out of a promise that was already meant for you.</p>`,
    keyVerse:{ ref:'Numbers 14:8', text:'If the LORD delights in us, he will bring us into this land and give it to us, a land that flows with milk and honey.' },
    scriptureRefs:['Numbers 13','Numbers 14'] },
  { id:'bronze-serpent', year:-1407, displayYear:'~1407 BC', era:'exodus-conquest',
    icon:'🐍', title:'The Bronze Serpent',
    subtitle:'Look and live.',
    body:`<p>Late in the forty years of wandering. The shortcut around Edom is long and hot and the people break, again. "Why have you brought us up out of Egypt to die in the wilderness? There is no food and no water, and we loathe this worthless food." Manna is "worthless food" now — the same bread of heaven they once cried out for. God sends fiery serpents into the camp. People are bitten. Many die.</p><p>The people repent. They ask Moses to pray. Moses prays. God's answer is strange — not antivenom, not removal of the snakes, but a sign. "Make a fiery serpent and set it on a pole, and everyone who is bitten, when he sees it, shall live." Moses fashions a serpent of bronze and lifts it up on a pole in the middle of the camp. Anyone bitten who turned their head to look — lived.</p><p>Fifteen hundred years later Jesus, talking with Nicodemus in the dark, would point straight back to this moment: "As Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up, that whoever believes in him may have eternal life." The sin-serpent dies on a pole. Whoever looks, lives. The cross is in the desert long before it's in Jerusalem.</p>`,
    whyMatters:`<p>Salvation is not earned by what you do. It is received by where you look. The most active soul in the room is the one bitten and dying who turns its head toward the Lifted One. Look at Him. You will live.</p>`,
    keyVerse:{ ref:'John 3:14-15', text:'And as Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up, that whoever believes in him may have eternal life.' },
    scriptureRefs:['Numbers 21:4-9','John 3:14-15'] },
  { id:'moses-death', year:-1406, displayYear:'~1406 BC', era:'exodus-conquest',
    icon:'🏔️', title:'Death of Moses',
    subtitle:'A leader sees the land but does not enter.',
    body:`<p>Forty years of wandering are over. The new generation stands at the eastern bank of the Jordan, looking across at Jericho. Moses is one hundred and twenty years old. Three times in Deuteronomy he preaches the Law one last time to a people about to enter the land. He sings a final song, blesses each of the tribes, and then God tells him to climb Mount Nebo.</p><p>From the top, God shows him the whole land — Gilead to Dan, Naphtali, Ephraim and Manasseh, Judah, the Negev, the plain of Jericho, all the way to the western sea. "This is the land of which I swore to Abraham, to Isaac, and to Jacob, saying, 'I will give it to your offspring.' I have let you see it with your eyes, but you shall not go over there." Years earlier Moses had struck a rock in anger when God told him to speak to it; this is the price. He sees from a distance what he will not enter.</p><p>Moses dies on the mountain, and the Lord buries him in the valley — no one knows the place to this day. Israel mourns for thirty days. Joshua takes up the staff. Centuries later, on a different mountain, Moses appears beside Elijah talking with Jesus about the exodus Jesus is about to accomplish in Jerusalem. He sees the Promised Land after all.</p>`,
    whyMatters:`<p>Not every promise lands in the timeline you imagined. Some of the most faithful saints see the land but do not enter it. God keeps His word — but His timing is His own. Faithfulness is finishing well even when someone else carries the work forward.</p>`,
    keyVerse:{ ref:'Deuteronomy 34:10', text:'There has not arisen a prophet since in Israel like Moses, whom the LORD knew face to face.' },
    scriptureRefs:['Deuteronomy 34'] },
  { id:'conquest', year:-1406, displayYear:'~1406 BC', era:'exodus-conquest',
    icon:'⚔️', title:'Joshua Crosses the Jordan',
    subtitle:'Forty years end at the Promised Land.',
    body:`<p>Joshua, formerly Moses' aide, now leads. God's first command to him is repeated four times in the opening chapter: "Be strong and courageous." Three days of preparation. Two spies sent to Jericho. Then on the morning of the crossing, the priests step into the Jordan carrying the Ark of the Covenant — the river is at flood stage from the spring melt — and the moment their feet touch the water, the river stops upstream at the city of Adam, and the riverbed stands dry.</p><p>The whole nation crosses, two million strong, while the priests stand mid-river. Twelve stones are carried out and set up on the western bank as a memorial — "When your children ask in time to come, 'What do these stones mean?' you shall let your children know, 'Israel crossed over this Jordan on dry ground.'" The river runs again behind them. There is no going back. Egypt is over. The wilderness is over. The land of promise is finally under their feet.</p><p>Forty years before, the parents had refused to cross. Now the children do. Every generation must decide for itself whether to walk into what God has prepared. The God who parted the Red Sea also parted the Jordan — different rivers, same word: nothing can stand between a faithful God and the people He is bringing home.</p>`,
    whyMatters:`<p>The thresholds in your life — the new job, the new marriage, the new step of obedience — usually look like floodwater. God's habit is to part the water as you step in, not before. The promise is on the other side, and the river always runs again behind you.</p>`,
    keyVerse:{ ref:'Joshua 1:9', text:'Have I not commanded you? Be strong and courageous. Do not be frightened, and do not be dismayed, for the LORD your God is with you wherever you go.' },
    scriptureRefs:['Joshua 3','Joshua 4'], relatedSiteId:'jericho', relatedStoryId:'jericho' },
  { id:'jericho-walls', year:-1406, displayYear:'~1406 BC', era:'exodus-conquest',
    icon:'🏛️', title:'The Walls of Jericho',
    subtitle:'Worship is the battle plan.',
    body:`<p>The first city in the land. Jericho's walls were thick enough to drive a chariot on top of, and the city had been there for thousands of years. Joshua is met outside the walls by the commander of the army of the Lord — sword drawn, on neither side, but God's side. Joshua falls on his face. He is told to take off his sandals, just as Moses was at the bush. This battle, like Sinai, is holy ground.</p><p>The plan is absurd. For six days the army is to circle the city once, in silence, with seven priests blowing rams' horns in front of the Ark. On the seventh day they are to circle seven times, and then on the seventh circle of the seventh day, when the priests blow a long blast, the people are to shout. That is the entire strategy. Worship is the battle plan. Trumpets, not siege engines. A shout, not a ram.</p><p>Six days pass. The morning of the seventh day comes. Seven slow circles, in the quiet of dawn. The long blast. The shout of a nation. And the wall, which had stood for centuries, falls down flat — straight down, not toppled outward — so that every soldier walks straight up over the rubble into the city. Rahab the prostitute and her family are spared. She marries an Israelite named Salmon and becomes part of the line that leads to David, and through David, to Jesus.</p>`,
    whyMatters:`<p>The walls that have stood for years in your life — the addictions, the unforgiveness, the family patterns — do not fall to your strength. They fall to obedience and worship done on repeat. Show up. Walk the circle. The seventh day is closer than you think.</p>`,
    keyVerse:{ ref:'Hebrews 11:30', text:'By faith the walls of Jericho fell down after they had been encircled for seven days.' },
    scriptureRefs:['Joshua 6','Hebrews 11:30'], relatedSiteId:'jericho', relatedStoryId:'jericho' },
  { id:'sun-stands', year:-1400, displayYear:'~1400 BC', era:'exodus-conquest',
    icon:'☀️', title:'The Sun Stands Still',
    subtitle:'God fights for Israel at Gibeon.',
    body:`<p>Joshua has just made peace with the Gibeonites — a treaty God did not authorize, but one He honors. When five Amorite kings hear that Gibeon has aligned with Israel, they form a coalition to destroy the city. Gibeon sends word to Joshua: "Do not relax your hand from your servants. Come up to us quickly and save us." Joshua marches all night from Gilgal — twenty miles uphill — and falls on the kings at dawn.</p><p>The LORD throws the coalition into panic. As they flee down the Beth-horon pass, hailstones from heaven strike them down — Scripture notes more die from the storm than from the sword. Then Joshua does something audacious. Standing in the sight of all Israel, he calls out: "Sun, stand still at Gibeon, and moon, in the Valley of Aijalon." And the sun stops. The moon stops. The day stretches and stretches until the battle is finished.</p><p>The verse that follows is one of the most arresting in Scripture: "There has never been a day like it before or since, when the LORD listened to a human voice." The God who hung the sun in the sky also paused it when His servant asked. The same God still listens. The strangest miracles in the Bible are not the moments when nature is suspended; they are the moments when a human voice is heard.</p>`,
    whyMatters:`<p>Heaven is more attentive than you realize. The God who can pause the sun for a battle He has already won is not too busy to hear what you're asking right now. You will not always get a stopped sun, but you will always get a listening God.</p>`,
    keyVerse:{ ref:'Joshua 10:14', text:'There has been no day like it before or since, when the LORD heeded the voice of a man, for the LORD fought for Israel.' },
    scriptureRefs:['Joshua 10:12-14'] },

  // ── ACT 4: JUDGES ─────────────────────────────────────────
  { id:'judges-cycle', year:-1380, displayYear:'~1380 BC', era:'judges',
    icon:'🌀', title:'The Cycle of Judges Begins',
    subtitle:'A repeating pattern of forgetting and rescue.',
    body:`<p>Joshua dies. His generation dies. "And there arose another generation after them who did not know the LORD or the work that he had done for Israel." Within a hundred years, the nation that watched the Red Sea split is worshipping the Baals. The book of Judges tells the story not as one decline but as a spiral — same pattern, deeper each turn.</p><p>The cycle is consistent and tragic. Israel forgets God and follows the gods of the surrounding nations. God hands them over to oppressors — Midianites, Philistines, Moabites, Ammonites. Israel suffers, cries out, repents. God raises up a deliverer — a "judge" — usually unlikely, sometimes flawed, who rescues the nation. There is peace for a generation. Then they forget again.</p><p>Twelve judges rise across roughly three hundred years: Othniel, Ehud, Shamgar, Deborah, Gideon, Tola, Jair, Jephthah, Ibzan, Elon, Abdon, Samson. The book ends with no leader at all — just a refrain repeated four times: "In those days there was no king in Israel. Everyone did what was right in his own eyes." The diagnosis of a culture in collapse is also a diagnosis of a human heart without God on the throne.</p>`,
    whyMatters:`<p>Forgetting is the most ordinary sin. One generation walks through the sea; the next builds an idol. The cure isn't more rules; it's a King — one your heart actually serves, who will not be forgotten when the next generation comes.</p>`,
    keyVerse:{ ref:'Judges 21:25', text:'In those days there was no king in Israel. Everyone did what was right in his own eyes.' },
    scriptureRefs:['Judges 2:10-19','Judges 21:25'] },
  { id:'deborah', year:-1200, displayYear:'~1200 BC', era:'judges',
    icon:'🌳', title:'Deborah & Barak',
    subtitle:'A prophetess leads under the palm tree.',
    body:`<p>For twenty years a Canaanite king named Jabin has oppressed Israel from his capital Hazor. His army commander Sisera has nine hundred iron chariots — the tanks of the bronze age — and Israel has nothing comparable. The people cry out. A woman named Deborah is judging Israel from beneath a palm tree in the hill country of Ephraim. She summons a man named Barak from up north.</p><p>"Has not the LORD, the God of Israel, commanded you: 'Go, gather your men at Mount Tabor... and I will draw out Sisera... and give him into your hand'?" Barak's reply is half-faith, half-fear: "If you will go with me, I will go; but if you will not go with me, I will not go." Deborah agrees, but tells him the glory of the kill will not be his — "for the LORD will sell Sisera into the hand of a woman." Ten thousand Israelites against nine hundred chariots; the Kishon River floods unexpectedly; the chariots bog down in mud; Israel routs them.</p><p>Sisera flees on foot to the tent of a woman named Jael, who welcomes him in, gives him milk, lets him fall asleep — and drives a tent peg through his head. The next chapter is the Song of Deborah, one of the oldest passages in the Bible. It celebrates not just the victory but every woman who showed up — the prophetess, the warrior, the tent-peg-driver. God uses whomever He pleases.</p>`,
    whyMatters:`<p>God is not constrained by who He's "supposed" to use. He raises up the women under palm trees, the men who say "only if you come with me," the housewives who pick up tent pegs. If you are willing, you are qualified — His Spirit makes up the rest.</p>`,
    keyVerse:{ ref:'Judges 4:9', text:'I will surely go with you. Nevertheless, the road on which you are going will not lead to your glory, for the LORD will sell Sisera into the hand of a woman.' },
    scriptureRefs:['Judges 4','Judges 5'] },
  { id:'gideon', year:-1170, displayYear:'~1170 BC', era:'judges',
    icon:'🐏', title:"Gideon's Fleece",
    subtitle:'A frightened man becomes a warrior.',
    body:`<p>The Midianites have been raiding Israel for seven years — sweeping in like locusts at harvest time, taking food, animals, and what little hope remains. Gideon is threshing wheat in a winepress, hidden so the Midianites won't see him. The angel of the Lord appears and says: "The LORD is with you, O mighty warrior." Gideon's first response is to argue — "If the LORD is with us, why has all this happened to us?" The angel does not back down.</p><p>God commissions him to tear down his father's altar to Baal (he does it at night, terrified, but he does it), then to gather an army against Midian. Gideon lays out a fleece on the threshing floor — dew on the fleece, dry on the ground; the next night the reverse. God answers both ways. Then God whittles. Thirty-two thousand soldiers volunteer. God says it's too many. The fearful go home — twenty-two thousand leave. Ten thousand are too many. A water test reduces it to three hundred.</p><p>The strategy is theater. Three hundred men with torches inside clay jars, ringing the Midianite camp at midnight. At Gideon's signal they smash the jars and blow rams' horns. The Midianites wake in panic, draw swords on each other in the dark, and flee. The victory is so impossible that no one could mistake whose victory it was. God shrinks the army until only He can be the explanation.</p>`,
    whyMatters:`<p>God often shrinks your resources before He fights your battle, because He is not interested in shared credit. The "winepress" where you've been hiding is not where He plans to leave you. He calls you mighty before you feel it.</p>`,
    keyVerse:{ ref:'Judges 6:12', text:'The angel of the LORD appeared to him and said to him, The LORD is with you, O mighty man of valor.' },
    scriptureRefs:['Judges 6','Judges 7'], relatedStoryId:'gideon-300' },
  { id:'ruth', year:-1100, displayYear:'~1100 BC', era:'judges',
    icon:'🌾', title:'Ruth & Boaz',
    subtitle:'Loyalty writes its way into the messianic line.',
    body:`<p>A famine in Bethlehem ("house of bread") sends an Israelite family to Moab — across the Jordan, among enemies. The father dies there. Both sons marry Moabite women, then both sons die too. Three widows are left: Naomi the Israelite, Ruth and Orpah the Moabites. Naomi decides to go home. Orpah, tearfully, turns back. Ruth makes one of the most stunning declarations of loyalty in the Bible: "Where you go I will go, and where you lodge I will lodge. Your people shall be my people, and your God my God."</p><p>They arrive in Bethlehem at the start of barley harvest, penniless. Ruth goes out to glean — the Old Testament welfare law that let the poor pick up grain left at the edges of a field. She lands, "as it happened," in the field of Boaz, a wealthy kinsman of Naomi's late husband. He notices her. He instructs his workers to leave extra grain on purpose. He invites her to his table for lunch.</p><p>Naomi reads the signs and coaches Ruth to ask Boaz to redeem the family — to marry her under the kinsman-redeemer law. He gladly does. They have a son named Obed. Obed has a son named Jesse. Jesse has a son named David. And four generations later a Moabite widow named Ruth shows up in the genealogy of Jesus Christ. The God of Israel writes the foreigner straight into the Messianic line.</p>`,
    whyMatters:`<p>You are never too far outside, too foreign, too widowed, too late. God writes outsiders into the center of His story on purpose. The kindness shown to you, and the kindness you show in return, may turn out to be the doorway to a redemption you couldn't have planned.</p>`,
    keyVerse:{ ref:'Ruth 1:16', text:'Where you go I will go, and where you lodge I will lodge. Your people shall be my people, and your God my God.' },
    scriptureRefs:['Ruth 1:16-17','Matthew 1:5'], relatedStoryId:'ruth-naomi' },
  { id:'samson', year:-1085, displayYear:'~1085 BC', era:'judges',
    icon:'💪', title:'Samson & Delilah',
    subtitle:'Strength wasted, then redeemed at the end.',
    body:`<p>An angel appears to a barren Israelite woman and announces her coming son. The boy is to be a Nazirite from the womb — no wine, no haircut, no contact with the dead. He will "begin to save Israel from the hand of the Philistines." The boy is Samson. He grows up with terrifying strength — tearing a lion apart with his bare hands, killing a thousand Philistines with the jawbone of a donkey, walking off with the gates of Gaza on his back. But his weakness is also obvious: he loves Philistine women.</p><p>Delilah is the third. She is paid by the Philistine lords to discover the secret of his strength. He toys with her three times — false answers, each one tested while he sleeps. The fourth time, worn down by her tears and pressure, he tells her the truth: his hair has never been cut; if it is, his strength will go. She lulls him to sleep on her lap, calls for a man to shave his head, and wakes him with the words "The Philistines are upon you, Samson." His strength is gone. The Philistines gouge out his eyes and put him to work grinding grain in the prison at Gaza.</p><p>The Philistines gather thousands in the temple of Dagon to celebrate. They call for Samson to entertain them. He asks the boy leading him to place his hands on the central pillars. He prays a one-line prayer — "O Lord GOD, please remember me and please strengthen me only this once" — and pushes. Three thousand Philistines die with him. Hebrews names him among the heroes of faith. Even a wasted life, surrendered in the final hour, lands among the saints.</p>`,
    whyMatters:`<p>God's gifts are not the same as God's friendship. Many people have strength and waste it. Many have lost almost everything before they finally pray a real prayer. The good news is that no chapter of your story is wasted with God if you are willing to come back to Him at the end.</p>`,
    keyVerse:{ ref:'Judges 16:28', text:'Then Samson called to the LORD and said, O Lord GOD, please remember me and please strengthen me only this once, O God.' },
    scriptureRefs:['Judges 13','Judges 16:23-30'], relatedStoryId:'samson-delilah' },
  { id:'hannah', year:-1080, displayYear:'~1080 BC', era:'judges',
    icon:'🙏', title:"Hannah's Prayer",
    subtitle:'A bitter woman births a prophet.',
    body:`<p>Elkanah has two wives. Peninnah has children. Hannah has none. Year after year the family travels up to the tabernacle at Shiloh to offer sacrifices, and year after year Peninnah provokes Hannah until she weeps and cannot eat. Elkanah, well-meaning and tone-deaf, asks: "Hannah, why do you weep? Am I not more to you than ten sons?" He is not.</p><p>One year at Shiloh, Hannah goes to the tabernacle alone and prays so intensely that her lips move without sound. Eli the high priest, slumped at the doorpost, thinks she's drunk and rebukes her. She corrects him: "I am a woman troubled in spirit... I have been pouring out my soul before the LORD." She has vowed that if God gives her a son, she will give him back — fully dedicated to the LORD as a Nazirite. Eli blesses her: "Go in peace, and the God of Israel grant your petition."</p><p>She conceives. She names the boy Samuel — "asked of God." After weaning him she walks him back to Shiloh herself and hands him to Eli with these words: "For this child I prayed, and the LORD has granted me my petition." Then she sings a song that anticipates Mary's Magnificat almost word for word — about a God who lifts up the poor and brings down the proud. Samuel will become the last judge and the first kingmaker. Every revolution starts in a sanctuary somewhere, with a woman who refused to be told her tears didn't matter.</p>`,
    whyMatters:`<p>God hears prayers that you cannot get out loud. The tears no one understands. The petitions you've made a hundred times. The vows you make when you mean them. Hannah's son shaped a nation — because his mother kept praying when no one was listening but God.</p>`,
    keyVerse:{ ref:'1 Samuel 1:27', text:'For this child I prayed, and the LORD has granted me my petition that I made to him.' },
    scriptureRefs:['1 Samuel 1','1 Samuel 2:1-10'] },
  { id:'samuel-anoints', year:-1050, displayYear:'~1050 BC', era:'judges',
    icon:'🕯️', title:'Samuel — The Last Judge',
    subtitle:'A boy hears God in the dark.',
    body:`<p>Samuel grows up in the tabernacle under Eli. As a boy he hears his name called in the night and answers what Eli teaches him to say: "Speak, LORD, for your servant is listening." It is the prayer that will define his life. He grows into Israel's last judge and the first true prophet since Moses — "And all Israel from Dan to Beersheba knew that Samuel was established as a prophet of the LORD."</p><p>When Samuel is old, the elders of Israel come and demand a king "like all the nations." Samuel takes it personally and brings it to God. God tells him: "They have not rejected you, but they have rejected me from being king over them." Samuel warns the people what a king will do — conscript their sons, tax their fields, take their daughters — but they insist. Samuel anoints Saul with oil, then later, when Saul fails, walks to Bethlehem and anoints a forgotten shepherd boy named David.</p><p>His last words to Israel are a farewell address that doubles as a confession of integrity: "Whose ox have I taken? Whom have I defrauded? I am here; testify against me." No one can. Samuel bridges the era of judges and the era of kings. He is the last clear voice before the centuries of monarchy begin, and he hands the kingdom to a Davidic line that will eventually deliver the King no one is asking for yet.</p>`,
    whyMatters:`<p>God still raises up people who say, "Speak, LORD, I am listening." In an age that wants kings like the nations, He looks for hearts willing to be quiet long enough to hear Him. Listening is the first act of faithful leadership.</p>`,
    keyVerse:{ ref:'1 Samuel 3:10', text:'Then the LORD came and stood, calling as at other times, Samuel! Samuel! And Samuel said, Speak, for your servant hears.' },
    scriptureRefs:['1 Samuel 3','1 Samuel 8'], relatedStoryId:'samuel-anoints-david' },

  // ── ACT 5: UNITED KINGDOM ────────────────────────────────
  { id:'saul-crowned', year:-1050, displayYear:'~1050 BC', era:'united-kingdom',
    icon:'👑', title:'Saul, the First King',
    subtitle:'Tall, hidden, then crowned.',
    body:`<p>The elders demand a king. God gives them Saul. He looks the part — tall, head and shoulders above any Israelite, from the tribe of Benjamin, the son of a wealthy man. He is also genuinely humble at first: when Samuel calls for him at his coronation, Saul is hiding among the baggage. Samuel anoints him with oil, kisses him, and says, "The LORD has anointed you to be prince over his people Israel."</p><p>Saul starts well. He rescues the city of Jabesh-gilead from the Ammonites. He unites the tribes. But two early failures show the crack. At Gilgal, when Samuel is late, Saul offers the burnt offering himself instead of waiting — usurping the priest's role. Later, commanded to destroy the Amalekites completely, he spares their king Agag and the best livestock, then tries to justify it as worship. Samuel's verdict: "To obey is better than sacrifice... Because you have rejected the word of the LORD, he has also rejected you from being king."</p><p>The rest of Saul's reign is a long unraveling — jealousy of David, spear-throwing, witch-of-Endor consultations, manic depression alternating with bursts of brilliance. He dies on Mount Gilboa, falling on his own sword to avoid Philistine capture. The first king of Israel ends in suicide because he could not bring himself to obey the One who put him on the throne.</p>`,
    whyMatters:`<p>Looking the part isn't the same as being faithful. The most dangerous moment in any anointing is the first time you decide your version of obedience is good enough. Saul's tragedy wasn't lack of talent — it was unwillingness to be told no.</p>`,
    keyVerse:{ ref:'1 Samuel 15:22', text:'To obey is better than sacrifice, and to listen than the fat of rams.' },
    scriptureRefs:['1 Samuel 10','1 Samuel 15'] },
  { id:'goliath', year:-1025, displayYear:'~1025 BC', era:'united-kingdom',
    icon:'🪨', title:'David & Goliath',
    subtitle:'A shepherd boy and five smooth stones.',
    body:`<p>The Philistines and Israel are camped across a valley from each other. For forty days, twice a day, a giant named Goliath of Gath comes down into the valley and roars his challenge: "Choose a man for yourselves, and let him come down to me." Six cubits and a span tall — over nine feet — with bronze armor weighing one hundred and twenty-five pounds. Israel's army, including King Saul, freezes.</p><p>David is a teenager, the youngest of eight brothers, sent by his father to bring bread and cheese to his three oldest brothers at the front. He hears the giant taunting. He asks the question no one else dares to ask: "Who is this uncircumcised Philistine, that he should defy the armies of the living God?" Saul tries to put his own armor on him. It does not fit. David goes down to the brook, picks five smooth stones, and walks out to meet the giant with a sling and his shepherd's staff.</p><p>The giant curses. David shouts back: "You come to me with a sword and with a spear and with a javelin, but I come to you in the name of the LORD of hosts... that all the earth may know that there is a God in Israel." One stone. The giant falls forward, face to the ground. David uses the giant's own sword to take his head. The Israelite army, suddenly remembering what it is, routs the Philistines. A teenage shepherd has shown them what was possible if anyone had been willing.</p>`,
    whyMatters:`<p>The giant in your valley isn't fought with the armor of others. It's fought with what God has already given you to use, in His name, on behalf of His people. The question is rarely whether the giant is big enough; it is whether anyone is willing.</p>`,
    keyVerse:{ ref:'1 Samuel 17:45', text:'You come to me with a sword and with a spear and with a javelin, but I come to you in the name of the LORD of hosts, the God of the armies of Israel, whom you have defied.' },
    scriptureRefs:['1 Samuel 17'], relatedStoryId:'david-goliath' },
  { id:'david', year:-1010, displayYear:'~1010 BC', era:'united-kingdom',
    icon:'👑', title:'King David',
    subtitle:"A man after God's own heart, flawed and forgiven.",
    body:`<p>Saul is dead on Mount Gilboa. Israel is fractured. The tribe of Judah crowns David at Hebron; the rest of the tribes back Saul's son Ish-bosheth. After seven years of civil war, all twelve tribes finally gather to David and anoint him king. He is thirty years old. He will reign forty.</p><p>Under David, Israel becomes a real kingdom. He captures the Jebusite stronghold of Jerusalem and makes it the capital — a city belonging to no single tribe. He brings the Ark there. He plans the Temple his son will build. He composes seventy-three of the Psalms — laments, praise, repentance, war, longing. The Bible's prayer book is largely written by this one man.</p><p>The defining moment of his reign is 2 Samuel 7. David wants to build God a house. God instead promises to build David a house — a dynasty: "Your throne shall be established forever." That promise outlives David by a thousand years. When the angel appears to Mary, the announcement begins: "The Lord God will give to him the throne of his father David, and he will reign over the house of Jacob forever." The shepherd boy from Bethlehem becomes the ancestor of the Shepherd from Bethlehem.</p>`,
    whyMatters:`<p>God's promises run on His timeline, not yours. A throne promised to a shepherd took a thousand years to flower into the eternal King of Bethlehem. The faithfulness God shows in your small story is the same faithfulness that runs the long ones.</p>`,
    keyVerse:{ ref:'2 Samuel 7:16', text:'And your house and your kingdom shall be made sure forever before me. Your throne shall be established forever.' },
    scriptureRefs:['1 Samuel 16','2 Samuel 7'], relatedSiteId:'jerusalem' },
  { id:'ark-jerusalem', year:-1000, displayYear:'~1000 BC', era:'united-kingdom',
    icon:'📦', title:'The Ark Comes to Jerusalem',
    subtitle:'A king dances before God in the streets.',
    body:`<p>For decades the Ark of the Covenant has been in obscurity — first captured by the Philistines, then returned, then parked in the household of a man named Abinadab for twenty years. David, newly enthroned in Jerusalem, decides the presence of God should sit at the heart of the capital. His first attempt ends badly: an ox stumbles, a man named Uzzah reaches out to steady the Ark, and dies on the spot. The Ark was never meant to be touched by hands.</p><p>Three months later, David tries again — this time according to the Law, carried on the shoulders of Levites with poles through gold-overlaid rings, with sacrifices every six steps. The Ark enters Jerusalem to shouts and trumpets. David, dressed in a simple linen ephod, dances "with all his might" before the LORD — the king of Israel looking like a worshipper, not a king. His wife Michal watches from a window and despises him for it.</p><p>The Ark is placed inside a tent David has pitched on Mount Zion. Sacrifices are offered. Bread, dates, and raisin cakes are distributed to every man, woman, and child in Israel. The presence of God has come home to His city. Michal will go childless to her grave for her contempt. David will go on dancing — the principle of his reign now established: the king of Israel is always, first, a worshipper.</p>`,
    whyMatters:`<p>The center of your life is whatever you build the city around. David put worship at the center because he knew he was a king who would otherwise build it around himself. The dance before God is never beneath you. It is what kings are for.</p>`,
    keyVerse:{ ref:'2 Samuel 6:14', text:'And David danced before the LORD with all his might. And David was wearing a linen ephod.' },
    scriptureRefs:['2 Samuel 6'] },
  { id:'bathsheba', year:-990, displayYear:'~990 BC', era:'united-kingdom',
    icon:'💔', title:"David's Sin & Repentance",
    subtitle:'The greater the man, the deeper the fall.',
    body:`<p>"In the spring of the year, when kings go out to battle, David sent Joab..." The narrator's tone is already cold. David is on the roof of the palace one evening when he should have been with his army. He sees a woman bathing. He inquires; he is told she is Bathsheba, the wife of Uriah the Hittite, one of his elite soldiers currently fighting his war. He sends for her. He sleeps with her. She conceives.</p><p>The cover-up is methodical. David calls Uriah home from the front and tries to get him to sleep with his wife so the timing will look natural. Uriah refuses — out of loyalty to his fellow soldiers in the field. David tries again the next night with wine. Uriah still refuses. So David sends him back to Joab with sealed orders to put him in the heaviest fighting and withdraw — and Uriah dies. David takes Bathsheba into his house. A year passes. He thinks he has gotten away with it.</p><p>The prophet Nathan walks in with a story about a rich man who steals a poor man's only lamb. David rages: the man deserves to die. Nathan turns: "You are the man." David collapses into repentance — Psalm 51, the most quoted prayer of confession in human history: "Create in me a clean heart, O God." He is forgiven. He is not exempted. The child dies. His own household will be torn by violence and rebellion for the rest of his life. Sin forgiven is not sin without consequences. Yet the line that runs to Jesus passes through David and Bathsheba — Solomon. Mercy keeps writing even on broken pages.</p>`,
    whyMatters:`<p>The greater the gift, the deadlier the unaccountable evening. Forgiveness is real and immediate when you come back; consequences are also real. The same grace that lets you write Psalm 51 still asks you to walk through what your choices set in motion. Both are mercy.</p>`,
    keyVerse:{ ref:'Psalm 51:10', text:'Create in me a clean heart, O God, and renew a right spirit within me.' },
    scriptureRefs:['2 Samuel 11','2 Samuel 12','Psalm 51'] },
  { id:'solomon-crowned', year:-970, displayYear:'~970 BC', era:'united-kingdom',
    icon:'⚖️', title:'Solomon Asks for Wisdom',
    subtitle:'God offers anything. He asks for understanding.',
    body:`<p>David is old. His older son Adonijah has tried to seize the throne. With Nathan and Bathsheba's quick intervention, David designates Solomon — and Solomon is crowned with oil at the Gihon Spring while Adonijah's banquet is still underway. Solomon is perhaps twenty years old. He inherits a kingdom at the peak of its power and a father's parting words: "Be strong, and show yourself a man. Keep the charge of the LORD your God."</p><p>Early in his reign Solomon goes up to Gibeon to sacrifice. That night God appears to him in a dream: "Ask what I shall give you." Solomon could ask for long life, riches, the death of his enemies. Instead he asks: "Give your servant therefore an understanding mind to govern your people, that I may discern between good and evil." God is pleased. Wisdom is granted — and wealth and honor besides.</p><p>The famous test comes soon after. Two prostitutes appear before him, both claiming the same living infant. Solomon calls for a sword. "Divide the living child in two, and give half to the one and half to the other." The real mother cries out: "Oh, my lord, give her the living child, and by no means put him to death." The false mother agrees to the split. Solomon hands the baby to the true mother. The story spreads through Israel; the people see that the wisdom of God is in him to do justice. The wisest king in the world's history begins by asking for help.</p>`,
    whyMatters:`<p>What you ask for when God says, "Ask anything," reveals what you actually believe matters. Wisdom is still on the table. So is the courage to ask for it instead of for the things you think wisdom would buy you.</p>`,
    keyVerse:{ ref:'1 Kings 3:9', text:'Give your servant therefore an understanding mind to govern your people, that I may discern between good and evil.' },
    scriptureRefs:['1 Kings 3'], relatedStoryId:'solomon-two-mothers' },
  { id:'solomon-temple', year:-957, displayYear:'~957 BC', era:'united-kingdom',
    icon:'🏛️', title:"Solomon's Temple",
    subtitle:'Heaven and earth meet on Mount Moriah.',
    body:`<p>The Temple takes seven years to build. Solomon contracts with Hiram, the king of Tyre, for cedar from Lebanon. Stones are quarried and dressed at the source so that "neither hammer nor axe nor any tool of iron was heard in the house while it was being built." Tens of thousands of laborers move materials by sea and by land. Bezalel's pattern in the tabernacle is scaled up to permanence — gold-overlaid walls, two great cherubim of olive wood in the inner sanctuary, ten golden lampstands, twelve oxen of cast bronze supporting an enormous basin.</p><p>The dedication is the high point of the Old Testament. The Ark is carried in by the priests, the cherubim cover it with their wings, the priests withdraw — and the cloud of glory descends so densely that the priests cannot stand to minister. Solomon kneels on a bronze platform before the whole assembly, lifts his hands toward heaven, and prays one of the most beautiful prayers in Scripture. He acknowledges that the heaven of heavens cannot contain God, much less this house. He asks God to hear from heaven when His people pray toward this place — when there is famine, when there is defeat, when they sin, when foreigners come, when they are far from home.</p><p>God answers with fire from heaven that consumes the sacrifices. Israel celebrates for seven days. But the Temple itself is a sign, not the destination. Centuries later Jesus would stand at this same site and predict its destruction. He would also call His own body "this temple," and promise that anyone in Him would become a temple too. The cloud that filled the house in Solomon's day was looking forward to Pentecost — when the same Spirit would fill not stone, but people.</p>`,
    whyMatters:`<p>The God who once filled a building of cedar and gold now fills hearts of flesh. The temple is not a place you visit; it is the body you live in. The same glory that overwhelmed Solomon's priests dwells in any believer who says yes to the Spirit.</p>`,
    keyVerse:{ ref:'1 Kings 8:27', text:'But will God indeed dwell on the earth? Behold, heaven and the highest heaven cannot contain you; how much less this house that I have built!' },
    scriptureRefs:['1 Kings 6','1 Kings 8'], relatedSiteId:'temple-mount' },
  { id:'queen-sheba', year:-950, displayYear:'~950 BC', era:'united-kingdom',
    icon:'💎', title:'The Queen of Sheba',
    subtitle:'Wisdom that reaches the ends of the earth.',
    body:`<p>Word of Solomon's wisdom and wealth reaches the kingdom of Sheba — somewhere on the southern Arabian Peninsula or in Ethiopia, the limit of the known world. The queen of Sheba does what no monarch was expected to do: she packs a camel train of spices, gold, and precious stones, and travels north over a thousand miles to test him with "hard questions."</p><p>She asks. He answers. Everything. "There was nothing hidden from the king that he could not explain to her." She walks his palace, eats at his table, watches his servants, hears the songs of his musicians, sees the burnt offerings going up to the LORD. The text says quietly: "there was no more breath in her." She is left without words.</p><p>Her testimony is striking: "Behold, the half was not told me. Your wisdom and prosperity surpass the report that I heard. Happy are your men! Happy are these your servants, who continually stand before you and hear your wisdom!" Then she blesses the LORD of Israel — a Gentile queen proclaiming the God of Israel before the king of Israel. A thousand years later Jesus would say: "The queen of the South will rise up at the judgment with this generation and condemn it, for she came from the ends of the earth to hear the wisdom of Solomon, and behold, something greater than Solomon is here."</p>`,
    whyMatters:`<p>If a foreign queen would travel a thousand miles to hear Solomon, what should it look like to come to the Greater-Than-Solomon who is offering Himself for free? The hunger to learn is honored by God — especially when it brings someone from far away to the King who is wisdom Himself.</p>`,
    keyVerse:{ ref:'1 Kings 10:7', text:'I did not believe the reports until I came and my own eyes had seen it. And behold, the half was not told me. Your wisdom and prosperity surpass the report that I heard.' },
    scriptureRefs:['1 Kings 10','Matthew 12:42'] },

  // ── ACT 6: DIVIDED KINGDOM ────────────────────────────────
  { id:'kingdom-split', year:-930, displayYear:'~930 BC', era:'divided-kingdom',
    icon:'⚡', title:'The Kingdom Splits',
    subtitle:'North (Israel) vs. South (Judah).',
    body:`<p>Solomon's later years are not what his early years promised. He marries seven hundred wives and three hundred concubines — many from surrounding nations — and his heart, the writer tells us bluntly, is "not wholly true to the LORD his God, as was the heart of David his father." High places spring up around Jerusalem for Chemosh and Molech and Ashtoreth. God warns him that the kingdom will be torn from his son, though for David's sake one tribe will remain.</p><p>Solomon dies. His son Rehoboam goes to Shechem to be crowned. The northern tribes come with a request: "Your father made our yoke heavy. Now lighten the hard service of your father and his heavy yoke on us, and we will serve you." Rehoboam consults the old men, who counsel patience. He then consults the young men of his own court, who counsel arrogance: "Tell them my little finger is thicker than my father's thighs." He picks the young men.</p><p>The ten northern tribes break off under Jeroboam. Two kingdoms. Two capitals — Jerusalem in the south, soon Samaria in the north. Two royal lines, two trajectories, two centuries before the north is exiled and three before the south follows. The promise to David survives only in the south, in the tribe of Judah, where one descendant after another will sit on the throne until the Davidic line itself goes underground — only to reemerge in a stable in Bethlehem.</p>`,
    whyMatters:`<p>Pride lights fires that take centuries to put out. The decisions of one moment — by Solomon, by Rehoboam — fracture a nation for generations. God is patient with kings, but never indifferent to compromise. The price for refusing to listen is usually paid by the people you were supposed to lead.</p>`,
    keyVerse:{ ref:'1 Kings 12:14', text:'My father made your yoke heavy, but I will add to your yoke. My father disciplined you with whips, but I will discipline you with scorpions.' },
    scriptureRefs:['1 Kings 12'] },
  { id:'jeroboam-calves', year:-930, displayYear:'~930 BC', era:'divided-kingdom',
    icon:'🐂', title:"Jeroboam's Golden Calves",
    subtitle:'Politics builds rival worship.',
    body:`<p>Jeroboam now rules ten tribes from the north. He has a political problem: his people will still travel south to Jerusalem to worship at the Temple three times a year for the festivals. He is afraid that contact will eventually pull them back to the house of David. So he invents an alternate religion designed to keep his subjects home.</p><p>He sets up two golden calves — one at Bethel in the south of his kingdom, one at Dan in the far north — and announces: "Behold your gods, O Israel, who brought you up out of the land of Egypt." It is a deliberate echo of Aaron's sin at Sinai, and a deliberate replacement for Jerusalem. He builds shrines on high places, ordains priests who are not from the tribe of Levi, invents a festival in the eighth month to compete with the LORD's festival in the seventh.</p><p>Scripture's verdict on every king who follows Jeroboam in the north reduces to a single line, repeated like a drumbeat through 1 and 2 Kings: "He did what was evil in the sight of the LORD and walked in the way of Jeroboam, in his sin which he made Israel to sin." Not one of the nineteen northern kings reverses it. The political solution that "kept the people home" is the religious cancer that finally kills the northern kingdom two centuries later. State-managed faith always cuts its own throat in the end.</p>`,
    whyMatters:`<p>Worship engineered for convenience always corrupts the worshipper. The God you can manage is not the God who saves. Beware the religion you invent because the real one demands too much.</p>`,
    keyVerse:{ ref:'1 Kings 12:28', text:'And the king took counsel and made two calves of gold. And he said to the people, You have gone up to Jerusalem long enough. Behold your gods, O Israel, who brought you up out of the land of Egypt.' },
    scriptureRefs:['1 Kings 12:25-33'] },
  { id:'elijah', year:-870, displayYear:'~870 BC', era:'divided-kingdom',
    icon:'🔥', title:'Elijah on Mount Carmel',
    subtitle:'Fire falls. Baal loses.',
    body:`<p>Ahab is king of Israel — the worst yet, married to Jezebel, a Sidonian princess who imports Baal worship wholesale into the northern kingdom. Four hundred fifty prophets of Baal eat at her table. Three and a half years into a drought Elijah called down — "There shall be neither dew nor rain these years, except by my word" — Elijah summons a public showdown at Mount Carmel. All Israel gathers on the mountain. Two altars are built. Two bulls are slaughtered. The God who answers by fire is God.</p><p>The prophets of Baal go first. From morning until noon they cry out, dance around the altar, gash themselves with knives. Elijah taunts them: "Cry aloud! Maybe your god is musing, or relieving himself, or on a journey, or asleep." Nothing. By afternoon they have collapsed in exhaustion. Elijah's turn. He has the people pour twelve jars of water over his altar — three full soakings — until the trench around it is overflowing. Then he prays a one-paragraph prayer: "O LORD, God of Abraham, Isaac, and Israel, let it be known this day that you are God in Israel."</p><p>The fire of the LORD falls. It consumes the bull, the wood, the stones, the soil, and licks up the water in the trench. The people fall on their faces: "The LORD, He is God! The LORD, He is God!" The prophets of Baal are seized. Elijah climbs the mountain to pray for rain; on the seventh attempt the servant sees a cloud the size of a man's hand. The drought breaks. Heaven opens. One faithful prophet has dragged a whole nation back across the line.</p>`,
    whyMatters:`<p>You do not have to be in the majority to be on the side of the truth. Elijah felt utterly alone. Heaven was not. The God who answered by fire still vindicates anyone willing to stand on His side at midday in front of everyone.</p>`,
    keyVerse:{ ref:'1 Kings 18:39', text:'And when all the people saw it, they fell on their faces and said, The LORD, he is God; the LORD, he is God.' },
    scriptureRefs:['1 Kings 18:20-40'], relatedSiteId:'mt-carmel', relatedStoryId:'elijah-carmel' },
  { id:'naboth', year:-860, displayYear:'~860 BC', era:'divided-kingdom',
    icon:'🍇', title:"Naboth's Vineyard",
    subtitle:"A king's covetousness becomes a queen's murder.",
    body:`<p>Naboth has a vineyard next to Ahab's palace in Jezreel. Ahab wants it for a vegetable garden. He offers to trade or buy. Naboth refuses — the vineyard is his ancestral inheritance, protected under the Law of Moses; selling it would mean disowning the portion God gave his family at the conquest. Ahab goes home, lies on his bed, turns his face to the wall, and refuses to eat. The king of Israel is sulking.</p><p>Jezebel finds him there. Her response is contempt for his weakness: "Do you now govern Israel? Arise, and eat bread and let your heart be cheerful; I will give you the vineyard." She writes letters in Ahab's name, seals them with his royal signet, and sends them to the elders of Naboth's own city. The orders are precise: proclaim a fast, seat Naboth at the head of the people, suborn two worthless men to accuse him of cursing God and the king, then take him outside the city and stone him. The elders obey.</p><p>Naboth is dead. His sons too, according to a later reference. Ahab gets his vineyard. Then Elijah walks into the garden. The prophet meets the king among the new vines, and the verdict is terrible: "In the place where dogs licked up the blood of Naboth shall dogs lick your own blood." It will all come to pass. Ahab will be killed in battle and dogs will lick his blood from the chariot. Jezebel will be thrown from a window and trampled by horses; when servants go to bury her, only her skull, feet, and palms remain. The God who hears every cry of every Naboth eventually answers.</p>`,
    whyMatters:`<p>Power that crushes the small does not get the last word. The God of Naboth keeps the records that no human court ever sees. Whatever has been taken from you in this life — by a king, by a system, by a quiet cruelty — He has not forgotten. Justice will run its full course.</p>`,
    keyVerse:{ ref:'1 Kings 21:19', text:'Thus says the LORD: In the place where dogs licked up the blood of Naboth shall dogs lick your own blood.' },
    scriptureRefs:['1 Kings 21'] },
  { id:'elisha', year:-850, displayYear:'~850 BC', era:'divided-kingdom',
    icon:'🌊', title:"Elisha's Double Portion",
    subtitle:"The prophet's mantle keeps falling.",
    body:`<p>Elijah's days are done. At the Jordan he rolls up his mantle and strikes the water — it parts. They cross. Elijah turns to Elisha: "Ask what I shall do for you, before I am taken from you." Elisha asks for a double portion of his master's spirit — the inheritance of the firstborn son. Then a chariot of fire and horses of fire come down between them; Elijah goes up in a whirlwind.</p><p>Elisha cries out — "My father, my father!" — picks up the fallen mantle, strikes the Jordan again, and asks aloud: "Where is the LORD, the God of Elijah?" The water parts a second time. The double portion has arrived. For sixty years Elisha walks among the people performing more miracles than any prophet between Moses and Christ — most of them mercy miracles, not judgment.</p><p>A widow's empty jar of oil keeps filling until her debt is paid. A Shunammite couple's promised son is given, dies, and is raised. Bitter water at Jericho becomes sweet. Naaman the Syrian commander dips seven times in the Jordan and his leprosy disappears. An iron axe head floats. Elisha's bones, even after his death, raise a corpse thrown into his tomb. Where Elijah burned, Elisha healed — both prophets of the same patient God.</p>`,
    whyMatters:`<p>You may not be Elijah, but you may be asked to be Elisha — to pick up the mantle someone else dropped, and ask "Where is the LORD?" with their God still on the throne. The mercy miracles tend to outlast the fire.</p>`,
    keyVerse:{ ref:'2 Kings 2:14', text:'Then he took the cloak of Elijah that had fallen from him and struck the water, saying, Where is the LORD, the God of Elijah? And when he had struck the water, the water was parted to the one side and to the other.' },
    scriptureRefs:['2 Kings 2','2 Kings 5'] },
  { id:'jonah', year:-785, displayYear:'~785 BC', era:'divided-kingdom',
    icon:'🐋', title:'Jonah & Nineveh',
    subtitle:'A reluctant prophet, a repenting city.',
    body:`<p>God tells Jonah, an Israelite prophet, to go preach against Nineveh — the capital of Assyria, Israel's bloodiest enemy. Nineveh has flayed cities and impaled their leaders on poles. Jonah does not refuse; he flees. He goes down to Joppa, finds a ship bound for Tarshish (the opposite direction), pays the fare, and goes down into the hold to sleep.</p><p>A storm gets up. The pagan sailors pray to their gods. The captain wakes Jonah, who finally tells them: "I am a Hebrew, and I fear the LORD, the God of heaven, who made the sea and the dry land." He tells them to throw him overboard. They try to row to land first; finally they obey. The sea calms. A great fish swallows Jonah. Three days and nights in the dark. From inside the fish he prays a psalm. The fish vomits him onto the beach.</p><p>This time Jonah obeys. He walks into the city of 120,000 with a one-sentence sermon: "Yet forty days, and Nineveh shall be overthrown." The entire city repents — king, nobles, peasants, even the animals. God relents. And Jonah is furious. He sits east of the city under a vine waiting for God to destroy them anyway. "I knew that you are a gracious God and merciful, slow to anger and abounding in steadfast love." The book ends with God's question — "Should not I pity Nineveh?" — and refuses to answer it for us. Jesus would later call His own three days in the tomb "the sign of Jonah."</p>`,
    whyMatters:`<p>God's mercy is going to be wider than you wanted it to be. The people you have rooted against in your heart may be the people He sends you to. Repentance you do not believe is possible will sometimes still happen — and the only question is whether you will be glad.</p>`,
    keyVerse:{ ref:'Jonah 4:2', text:'I knew that you are a gracious God and merciful, slow to anger and abounding in steadfast love, and relenting from disaster.' },
    scriptureRefs:['Jonah 1','Jonah 4'], relatedStoryId:'jonah' },
  { id:'amos-hosea', year:-760, displayYear:'~760 BC', era:'divided-kingdom',
    icon:'📯', title:'Amos & Hosea',
    subtitle:'Justice and faithful love, side by side.',
    body:`<p>The eighth century BC is a long, prosperous summer in the northern kingdom under Jeroboam II. Trade is good. The rich are getting richer. The Temple at Bethel is busy with feasts and burnt offerings. Then, into Bethel walks a southerner named Amos — a herdsman and a dresser of sycamore figs from the town of Tekoa. He has no prophetic pedigree. He has only a word.</p><p>Amos thunders. The rich "trample on the heads of the poor" and "sell the righteous for silver and the needy for a pair of sandals." Their religious festivals are a stench in God's nostrils because their courts are corrupt. "Let justice roll down like waters, and righteousness like an ever-flowing stream." The northern court tries to silence him. He keeps preaching. Forty years later the Assyrians arrive on schedule, and the prosperous kingdom Amos warned is over.</p><p>Beside him stands Hosea — a northern prophet given an unbearable assignment. "Go, take to yourself a wife of whoredom." He marries Gomer. She betrays him. She runs to other lovers and ends up on the slave block. God tells Hosea: "Go again, love a woman who is loved by another man and is an adulteress, even as the LORD loves the children of Israel." He buys her back at full price. Hosea's marriage is the parable: God's people prostitute themselves to other gods, and yet He keeps loving and redeeming.</p>`,
    whyMatters:`<p>Comfort makes us forget that God still cares whether the poor get justice. Sin makes us forget that God still loves and redeems. The same prophets who shout about both are showing us the same heart of God.</p>`,
    keyVerse:{ ref:'Amos 5:24', text:'But let justice roll down like waters, and righteousness like an ever-flowing stream.' },
    scriptureRefs:['Amos 5:24','Hosea 11:1-4'] },
  { id:'isaiah', year:-740, displayYear:'~740 BC', era:'divided-kingdom',
    icon:'📯', title:'Isaiah Prophesies the Messiah',
    subtitle:'A virgin, a child, a suffering servant.',
    body:`<p>Uzziah the king dies. Young Isaiah is in the Temple when he sees a vision that will mark him for life: the LORD seated on a throne, high and lifted up, the train of His robe filling the temple. Six-winged seraphim cry to one another: "Holy, holy, holy is the LORD of hosts; the whole earth is full of his glory!" The doorposts shake. Isaiah cries, "Woe is me! For I am lost; for I am a man of unclean lips." A seraph touches his lips with a coal from the altar. "Whom shall I send, and who will go for us?" Isaiah answers, "Here I am! Send me."</p><p>For forty years he prophesies through four kings of Judah. He confronts Ahaz when he is about to trust Assyria more than God. He stands beside Hezekiah when Sennacherib's army surrounds Jerusalem. He gives Israel some of the most ravishing promises in Scripture — a virgin will conceive and bear a son and call his name Immanuel; a great light will dawn on the people walking in darkness; a child will be born whose name is Wonderful Counselor, Mighty God, Everlasting Father, Prince of Peace.</p><p>Then in chapters 52 and 53, he sketches the Suffering Servant in detail seven centuries before Christ — pierced for our transgressions, crushed for our iniquities, bearing the iniquity of us all. The New Testament writers will quote no Old Testament book more often than Isaiah. The Messiah's biography is already written.</p>`,
    whyMatters:`<p>You will not see the holiness of God without seeing your own unclean lips. But once the coal touches you, the only sensible answer to "Whom shall I send?" is "Here I am." Worship and mission are two halves of the same vision.</p>`,
    keyVerse:{ ref:'Isaiah 6:8', text:'And I heard the voice of the Lord saying, Whom shall I send, and who will go for us? Then I said, Here I am! Send me.' },
    scriptureRefs:['Isaiah 9:6','Isaiah 53'], relatedStoryId:'isaiah-throne' },
  { id:'samaria-falls', year:-722, displayYear:'722 BC', era:'divided-kingdom',
    icon:'💥', title:'Northern Kingdom Falls',
    subtitle:'Assyria scatters Israel.',
    body:`<p>The warnings come for two hundred years. The northern kingdom has not had a single righteous king. Idolatry is institutional. The poor are crushed. The prophets have preached and been ignored, sometimes killed. The Assyrian empire has been rising in the east — the most efficient war machine in the ancient world — and finally Tiglath-Pileser and then Shalmaneser turn their gaze on Israel.</p><p>The siege of Samaria lasts three years. The city finally falls in 722 BC under Sargon II. The Assyrian policy is genius and brutal: they deport the upper classes wholesale and resettle the land with conquered peoples from elsewhere in the empire — so no captured nation can maintain its identity. The ten northern tribes are scattered across Mesopotamia and disappear from history as a coherent people. The foreigners brought in intermarry with the few Israelites left and become the Samaritans — the same Samaritans Jesus will scandalize His disciples by speaking to a thousand years later.</p><p>The narrator in 2 Kings 17 stops and explains why it happened. Not because Assyria was strong. Because Israel had abandoned the LORD. The same God who patiently warns is not the God who indefinitely delays. The exile of Israel is also a sermon — preached in real time to the southern kingdom that is watching, and not learning.</p>`,
    whyMatters:`<p>Warnings unheeded for two hundred years still come due. God's patience is not God's tolerance — it is a window for repentance, not a guarantee. Whatever He has been saying to you for years, it remains true today.</p>`,
    keyVerse:{ ref:'2 Kings 17:18', text:'Therefore the LORD was very angry with Israel and removed them out of his sight. None was left but the tribe of Judah only.' },
    scriptureRefs:['2 Kings 17'] },
  { id:'hezekiah-tunnel', year:-701, displayYear:'701 BC', era:'divided-kingdom',
    icon:'💧', title:"Hezekiah's Tunnel",
    subtitle:'Sennacherib besieges; God delivers.',
    body:`<p>Hezekiah is one of the few good kings of Judah — the one whose name Isaiah preaches under. By his reign, Assyria has wiped out the northern kingdom and is moving south. Sennacherib's army is unstoppable: forty-six fortified cities of Judah fall. Jerusalem is next. Hezekiah does two things at once — practical and prayerful. He cuts a 1,750-foot tunnel through bedrock to bring the Gihon Spring inside the city walls so the besiegers cannot starve them of water. (The tunnel is still walkable today.)</p><p>He also receives a letter from Sennacherib's commander Rabshakeh, shouted in Hebrew over the city wall so the soldiers will hear: "Do not let Hezekiah deceive you, for he will not be able to deliver you. Has any of the gods of the nations ever delivered his land out of the hand of the king of Assyria?" Hezekiah takes the letter into the Temple and spreads it before the LORD. He prays: "O LORD our God, save us, please, from his hand, that all the kingdoms of the earth may know that you, O LORD, are God alone."</p><p>Isaiah sends back word from the LORD that the Assyrian will not so much as shoot an arrow into the city. That night the angel of the LORD goes out and strikes 185,000 Assyrian soldiers in their camp. Sennacherib goes home in disgrace; he is later murdered by his own sons in the temple of Nisroch his god. Jerusalem stands. The infidel king who mocked the living God is dead in his pagan temple.</p>`,
    whyMatters:`<p>God is honored when you dig the tunnel AND spread the letter before Him. Faith does not despise practical preparation, and preparation does not replace prayer. Sometimes the deliverance is by angel; sometimes by tunnel; usually it is both.</p>`,
    keyVerse:{ ref:'2 Kings 19:19', text:'So now, O LORD our God, save us, please, from his hand, that all the kingdoms of the earth may know that you, O LORD, are God alone.' },
    scriptureRefs:['2 Kings 18-19','2 Chronicles 32'] },
  { id:'josiah-book', year:-621, displayYear:'621 BC', era:'divided-kingdom',
    icon:'📖', title:'Josiah Finds the Book',
    subtitle:'A lost scroll triggers revival.',
    body:`<p>Josiah becomes king of Judah at the age of eight. He grows up in a kingdom that has spent two generations forgetting God under his grandfather Manasseh — possibly the most wicked king in Judah's history. At sixteen Josiah begins to seek the God of David. At twenty he starts cleansing the land of idols. At twenty-six he commissions repairs to the neglected Temple.</p><p>During the renovation, the high priest Hilkiah finds a scroll buried in the rubble — the Book of the Law, probably Deuteronomy. He sends it to the king. Shaphan the scribe reads it aloud in the palace. Josiah tears his robes. "Great is the wrath of the LORD that is kindled against us, because our fathers have not obeyed the words of this book." He sends to the prophetess Huldah to ask what the LORD says. Her word is gentle and severe: judgment is coming, but not in Josiah's lifetime — because his heart was tender and he humbled himself.</p><p>Josiah leads the most thorough reform in Judah's history. Pagan altars destroyed, idolatrous priests deposed, the high places torn down, Passover celebrated for the first time in centuries. Josiah dies young at Megiddo. Within twenty-five years of his death, Jerusalem is in flames. The reform he led delays judgment. It does not cancel it. Yet his short faithful life is recorded as the standard: "Before him there was no king like him, who turned to the LORD with all his heart and with all his soul and with all his might."</p>`,
    whyMatters:`<p>One faithful generation can rediscover the Book and rebuild a culture, even if the next generation throws it all away. Your obedience is not wasted because the consequences aren't permanent. God remembers it permanently.</p>`,
    keyVerse:{ ref:'2 Kings 22:11', text:'When the king heard the words of the Book of the Law, he tore his clothes.' },
    scriptureRefs:['2 Kings 22','2 Kings 23'] },
  { id:'jeremiah', year:-627, displayYear:'627 BC', era:'divided-kingdom',
    icon:'😢', title:'Jeremiah, the Weeping Prophet',
    subtitle:'Called before he was born.',
    body:`<p>"Before I formed you in the womb I knew you, and before you were born I consecrated you; I appointed you a prophet to the nations." Jeremiah's call comes when he is barely old enough to argue against it: "Ah, Lord GOD! Behold, I do not know how to speak, for I am only a youth." God replies: "Do not say, 'I am only a youth'; for to all to whom I send you, you shall go, and whatever I command you, you shall speak."</p><p>For forty years he preaches to a Judah that will not listen. The kings ridicule him. The priests beat him. The court prophets call him a traitor. He is thrown into a cistern to die in the mud and pulled out by an Ethiopian eunuch. He buys a field as a sign of hope just as Jerusalem is about to fall. He watches the Temple burn, the city sacked, his people deported. He is dragged to Egypt against his will. He dies far from home.</p><p>Yet in the middle of all this destruction, he writes the promise that re-frames everything: "Behold, the days are coming, declares the LORD, when I will make a new covenant with the house of Israel and with the house of Judah... I will put my law within them, and I will write it on their hearts." Jesus, the night before He dies, picks up the cup and says, "This is the new covenant in my blood." The weeping prophet glimpsed the gospel from inside the wreckage.</p>`,
    whyMatters:`<p>Faithfulness is not measured by results in your lifetime. Jeremiah preached for forty years to people who would not listen, and his book has shaped two thousand years of believers since. The new-covenant promise he received in the rubble is still being kept.</p>`,
    keyVerse:{ ref:'Jeremiah 31:33', text:'For this is the covenant that I will make with the house of Israel after those days, declares the LORD: I will put my law within them, and I will write it on their hearts. And I will be their God, and they shall be my people.' },
    scriptureRefs:['Jeremiah 1:5','Jeremiah 31:31-34'] },

  // ── ACT 7: EXILE & RETURN ─────────────────────────────────
  { id:'jerusalem-falls', year:-586, displayYear:'586 BC', era:'exile-return',
    icon:'🔥', title:'Jerusalem Falls to Babylon',
    subtitle:'Temple burns. Judah exiled.',
    body:`<p>The siege lasts eighteen months. Nebuchadnezzar's army of Babylonians has surrounded the city. Inside, famine grows so severe that Lamentations records mothers boiling their own children. King Zedekiah finally tries to slip out at night through a gap in the wall. The Babylonians catch him on the plains of Jericho. They drag him to Riblah, force him to watch his sons executed, then put out his eyes. The last thing he ever sees is his children's death.</p><p>A month later, the Babylonian captain of the guard, Nebuzaradan, walks into Jerusalem. He burns the house of the LORD, the king's house, every great house in Jerusalem. He breaks down the walls. He takes the bronze pillars Solomon had named Jachin and Boaz, the bronze sea, all the temple utensils. The Ark of the Covenant disappears from the historical record forever. The exile is complete.</p><p>The survivors who can write sit by the irrigation canals of Babylon and weep, hanging their harps on the willow trees. "By the waters of Babylon, there we sat down and wept when we remembered Zion." Their captors mock them: "Sing us one of the songs of Zion!" They cannot. The Promised Land is empty of the people it was promised to. Yet seventy years from now, by name, a Persian named Cyrus will sign a decree sending them home. Even when God's discipline looks like the end of the story, He is already two empires ahead of the calendar.</p>`,
    whyMatters:`<p>When the worst happens — when the walls come down, the city burns, the line of kings stops — God is not finished. The exile is a comma in His sentence, not a period. The God who keeps His warnings also keeps His promises.</p>`,
    keyVerse:{ ref:'Lamentations 3:22-23', text:'The steadfast love of the LORD never ceases; his mercies never come to an end; they are new every morning; great is your faithfulness.' },
    scriptureRefs:['2 Kings 25','Psalm 137'], relatedStoryId:'exile-babylon' },
  { id:'ezekiel-bones', year:-585, displayYear:'~585 BC', era:'exile-return',
    icon:'💀', title:"Ezekiel's Valley of Dry Bones",
    subtitle:'Prophesy to the wind.',
    body:`<p>Ezekiel is a priest exiled to Babylon at age twenty-five, before he ever serves a day in the Temple. God calls him by the Chebar canal in the fifth year of the exile. He sees a vision of God's throne with wheels within wheels, four-faced living creatures, and a sapphire throne moving over them — and he understands that the glory of God is not bound to Jerusalem. God can ride His throne to Babylon.</p><p>The middle of his ministry he spends acting out hard signs — lying on his side for over a year, eating bread baked over dung, refusing to mourn when his wife dies — each a prophetic message to a deportee community that does not want to believe Jerusalem will actually fall. When the news finally comes that the city has burned, his mouth is opened and his ministry shifts from warning to hope.</p><p>Then comes the most famous vision in the book. The Spirit of the LORD carries him out and sets him down in a valley full of dry bones — "very many on the surface of the valley, and behold, they were very dry." God asks: "Son of man, can these bones live?" Ezekiel answers: "O Lord GOD, you know." God commands him to prophesy. He prophesies, and there is a rattling, and the bones come together. Sinews and flesh come on them. He prophesies to the breath: it enters them, they stand on their feet, an exceedingly great army. "These bones are the whole house of Israel." Resurrection — first of a nation thought dead, then, eventually, of every body in every grave.</p>`,
    whyMatters:`<p>God specializes in valleys of dry bones. The marriages, the careers, the souls, the prodigals you have written off as too far gone — these are exactly the bones He is asking you to prophesy over. The Spirit He sends is in the business of standing up armies that the world wrote off.</p>`,
    keyVerse:{ ref:'Ezekiel 37:5', text:'Behold, I will cause breath to enter you, and you shall live.' },
    scriptureRefs:['Ezekiel 37:1-14'], relatedStoryId:'dry-bones' },
  { id:'fiery-furnace', year:-580, displayYear:'~580 BC', era:'exile-return',
    icon:'🔥', title:'Shadrach, Meshach & Abednego',
    subtitle:'"Even if He does not, we will not bow."',
    body:`<p>Nebuchadnezzar erects a golden statue ninety feet tall on the plain of Dura. He gathers every official in the empire and decrees that when the music plays — horn, pipe, lyre, trigon, harp, bagpipe — every person must fall down and worship the statue. Anyone who does not will be thrown into a blazing furnace. The music plays. The empire bows. Except three young Hebrews — Shadrach, Meshach, and Abednego, exiles from Judah who have risen in Nebuchadnezzar's administration.</p><p>They are reported. The king summons them. He is willing to give them a second chance — "If you do not worship, you shall immediately be cast into a burning fiery furnace. And who is the god who will deliver you out of my hands?" Their answer is one of the most courageous in Scripture: "If this be so, our God whom we serve is able to deliver us from the burning fiery furnace, and he will deliver us out of your hand, O king. But if not, be it known to you, O king, that we will not serve your gods or worship the golden image that you have set up."</p><p>The king orders the furnace heated seven times hotter than usual. It is so hot that the soldiers who throw the three men in are killed by the flames. Nebuchadnezzar looks in — and rises in haste. "Did we not cast three men bound into the fire?" Yes, his counselors confirm. "But I see four men unbound, walking in the midst of the fire, and they are not hurt; and the appearance of the fourth is like a son of the gods." The three come out without even the smell of smoke on their clothes. The king who built the statue blesses the God of Israel.</p>`,
    whyMatters:`<p>"But if not" is the most important phrase in faith. Trust God to deliver you; refuse to bow if He doesn't. The furnace is where Christ tends to be most visible. He is not always early to keep you out; He is always present in the fire.</p>`,
    keyVerse:{ ref:'Daniel 3:17-18', text:'Our God whom we serve is able to deliver us from the burning fiery furnace, and he will deliver us out of your hand, O king. But if not, be it known to you, O king, that we will not serve your gods.' },
    scriptureRefs:['Daniel 3'], relatedStoryId:'fiery-furnace' },
  { id:'daniel', year:-560, displayYear:'~560 BC', era:'exile-return',
    icon:'🦁', title:"Daniel in the Lions' Den",
    subtitle:'Faith refined in foreign fire.',
    body:`<p>Daniel was taken to Babylon as a teenager in the first deportation, around 605 BC. He serves in the courts of three empires — Babylon under Nebuchadnezzar and his successors, then Media-Persia under Darius and Cyrus — for over seventy years. He never once compromises on what God has called him to. He resolves not to defile himself with the king's food. He prays toward Jerusalem three times a day with his windows open even when it is illegal.</p><p>Darius signs a decree under pressure from jealous officials: anyone who prays to any god or man except the king for thirty days will be thrown into the den of lions. Daniel hears the decree and does what he always does — goes to his upper room, opens his windows toward Jerusalem, and prays three times that day. He is reported. Darius is grieved, but the law cannot be revoked. The lions' den is sealed with the king's signet. Darius cannot sleep all night. At first light he runs to the den: "O Daniel, servant of the living God, has your God, whom you serve continually, been able to deliver you from the lions?" Daniel's answer comes up from the pit: "O king, live forever! My God sent his angel and shut the lions' mouths."</p><p>But Daniel's greatest gift to the church is the visions he records. Empires rise and fall — Babylon, Media-Persia, Greece, Rome — and one day the God of heaven sets up a kingdom that shall never be destroyed, a stone cut from a mountain not by human hands. He sees the Son of Man coming on the clouds of heaven and being given an everlasting kingdom by the Ancient of Days. Jesus quotes Daniel before the Sanhedrin the night He is condemned.</p>`,
    whyMatters:`<p>Faithfulness in a small repeated habit — Daniel opened the same window three times a day — outlasts every empire that tries to outlaw it. Lions cannot eat what God is preserving. Empires rise; the stone keeps growing.</p>`,
    keyVerse:{ ref:'Daniel 6:22', text:"My God sent his angel and shut the lions' mouths, and they have not harmed me, because I was found blameless before him." },
    scriptureRefs:['Daniel 6','Daniel 7:13-14'], relatedSiteId:'babylon', relatedStoryId:'daniel-lions' },
  { id:'cyrus-decree', year:-538, displayYear:'538 BC', era:'exile-return',
    icon:'🕊️', title:"Cyrus Sends Israel Home",
    subtitle:'God uses a Persian king.',
    body:`<p>Seventy years after Jerusalem fell. The Persian king Cyrus the Great has just conquered Babylon — and the LORD stirs up his spirit. He issues a decree that gets put in writing in two languages: "The LORD, the God of heaven, has given me all the kingdoms of the earth, and he has charged me to build him a house at Jerusalem, which is in Judah. Whoever is among you of all his people, may his God be with him, and let him go up." Anyone who stays is to send silver, gold, goods, and beasts as freewill offerings.</p><p>The shocking detail is that Isaiah had named Cyrus a hundred and fifty years before Cyrus was born. "Thus says the LORD to his anointed, to Cyrus, whose right hand I have grasped, to subdue nations before him and to loose the belts of kings... I call you by your name, I name you, though you do not know me." The God of Israel uses a pagan emperor as His instrument and tells His people, in advance, exactly which one.</p><p>About fifty thousand exiles take the long road home under Zerubbabel and Jeshua. They bring back the temple vessels Nebuchadnezzar took. They lay the foundation of a new Temple while old men who remembered the first one weep, because the new one is so much smaller. The journey of seventy years takes four months. The God of returning exiles is sometimes faster than the God of warning prophets — though He is always the same God.</p>`,
    whyMatters:`<p>God names His instruments by name long before they are born. The kings of the earth are tools in His hand whether they know it or not. The road home from any exile is shorter than the years that got you there once He decides it is time.</p>`,
    keyVerse:{ ref:'Isaiah 45:4', text:'For the sake of my servant Jacob, and Israel my chosen, I call you by your name, I name you, though you do not know me.' },
    scriptureRefs:['Isaiah 45:1-7','Ezra 1'] },
  { id:'second-temple', year:-516, displayYear:'516 BC', era:'exile-return',
    icon:'🏛️', title:'Second Temple Rebuilt',
    subtitle:'Smaller, but God dwells again.',
    body:`<p>The returnees lay the foundation, and they hold a dedication ceremony. The trumpets blow. Some of the older priests and elders who had seen Solomon's Temple weep loudly. The young ones, who only know stories, shout for joy. The noise is so jumbled the writer notes that observers could not distinguish weeping from rejoicing. Then opposition begins. The Samaritans offer to help; they are refused. They turn hostile, write letters to the Persian court, manage to halt construction for sixteen years.</p><p>God raises up two prophets, Haggai and Zechariah, to wake the people back up. "Is it a time for you yourselves to dwell in your paneled houses, while this house lies in ruins?" Haggai asks. The people get back to work. Four years of effort under Darius's friendlier reign, and the Temple is finished — March 12, 516 BC. Seventy years almost to the day after Solomon's Temple burned.</p><p>The dedication is bittersweet. There is no Ark of the Covenant — it has disappeared from history. There is no visible cloud of glory descending. Haggai promises that the glory of this latter house will be greater than the former — a strange promise on a smaller building — until five centuries later a teenage girl from Nazareth carries the actual glory of God in her body up these steps to dedicate her firstborn son. The Temple was waiting for Him all along.</p>`,
    whyMatters:`<p>The work that looks smaller than what came before may be the one God is preparing for the greater visit. The discouragement of the old men was real, but they were measuring the wrong house. Keep building.</p>`,
    keyVerse:{ ref:'Haggai 2:9', text:'The latter glory of this house shall be greater than the former, says the LORD of hosts. And in this place I will give peace.' },
    scriptureRefs:['Ezra 6','Haggai 2'] },
  { id:'esther', year:-478, displayYear:'~478 BC', era:'exile-return',
    icon:'👸', title:'Esther Saves Her People',
    subtitle:'"For such a time as this."',
    body:`<p>The setting is the Persian court of Xerxes (Ahasuerus). After Queen Vashti is deposed for refusing to be paraded in front of drunken nobles, a beauty contest is held to find a new queen. Hadassah — a Jewish orphan raised by her older cousin Mordecai, given the Persian name Esther — is among the women taken. Mordecai tells her not to reveal her people. She wins the king's favor. She is crowned.</p><p>A high official named Haman becomes a vizier. Mordecai refuses to bow to him. Haman, enraged, decides not just to kill Mordecai but to exterminate every Jew in the empire. He casts lots ("Purim") to pick the date. He convinces the king. Edicts go out. The Jews tear their clothes and fast. Mordecai sends word to Esther: she must go before the king uninvited — a capital offense — and plead. Her famous line back to him: "And who knows whether you have not come to the kingdom for such a time as this?"</p><p>She fasts three days. She approaches the king. He extends the golden scepter. She does not blurt her petition; she invites him and Haman to a banquet, then another. Between banquets, the king happens to be reading the royal records and finds an unrewarded act of loyalty by Mordecai. Haman is forced to lead his enemy through the streets in honor. At the second banquet she finally names Haman as the genocidal enemy. The king storms out. Haman is hanged on the gallows he built for Mordecai. Purim is celebrated every year to this day. God's name appears nowhere in the book. His hand is on every page.</p>`,
    whyMatters:`<p>You may be in the position you are in for a reason you cannot yet see. "For such a time as this" is rarely obvious until afterward. Risk what you have for the people you love; God's hand is moving even when His name isn't mentioned.</p>`,
    keyVerse:{ ref:'Esther 4:14', text:"For if you keep silent at this time, relief and deliverance will rise for the Jews from another place, but you and your father's house will perish. And who knows whether you have not come to the kingdom for such a time as this?" },
    scriptureRefs:['Esther 4:14','Esther 7'], relatedStoryId:'esther' },
  { id:'nehemiah-wall', year:-445, displayYear:'~445 BC', era:'exile-return',
    icon:'🧱', title:'Nehemiah Rebuilds the Wall',
    subtitle:'Prayer and a trowel.',
    body:`<p>Ninety years after the first wave returned. Jerusalem still has no walls. Nehemiah is the cupbearer to King Artaxerxes in Susa — a position of enormous trust. His brother Hanani comes from Jerusalem with news, and the news devastates him. The wall is still broken down, the gates burned. For days he weeps, fasts, and prays. Then he asks the king for permission and a leave of absence and timber from the royal forests. Artaxerxes grants all of it.</p><p>He arrives in Jerusalem and inspects the wall at night, alone, so opponents cannot organize against him. He summons the people: "Come, let us build the wall of Jerusalem, that we may no longer suffer derision." The work is organized by sections — each family or guild builds the section near their own house. Sanballat and Tobiah mock from the surrounding regions: "If a fox went up on it he would break down their stone wall." They graduate to plots — ambush, assassination, false letters claiming Nehemiah plans to rebel.</p><p>The work continues with armed guards beside the builders. "Each of the builders had his sword strapped at his side while he built." Half the men stand watch while half the men build. Fifty-two days from start to finish. When the dedication comes, two great choirs walk on top of the new wall in opposite directions and meet at the Temple. The joy of the people is heard from far away. The wall is not the goal. The wall is the protection so the work of becoming God's people can continue inside it.</p>`,
    whyMatters:`<p>What you protect determines what you become. Sometimes prayer requires a permit; sometimes ministry requires a wall; sometimes worship requires a sword strapped to the side of the builder. God uses both/and people.</p>`,
    keyVerse:{ ref:'Nehemiah 6:15-16', text:'So the wall was finished in fifty-two days. And when all our enemies heard of it, all the nations around us were afraid and fell greatly in their own esteem, for they perceived that this work had been accomplished with the help of our God.' },
    scriptureRefs:['Nehemiah 1','Nehemiah 6:15'], relatedStoryId:'nehemiah-wall' },
  { id:'ezra-law', year:-444, displayYear:'~444 BC', era:'exile-return',
    icon:'📜', title:'Ezra Reads the Law',
    subtitle:'A nation hears Scripture again.',
    body:`<p>The wall is finished. The people gather inside the Water Gate — the entire community, men and women and children old enough to understand. They have asked Ezra, the priest and scribe who returned from Babylon a few years before, to bring the Book. He stands on a wooden platform with thirteen Levites flanking him. He opens the scroll. Everyone stands.</p><p>From sunrise until midday — six hours — he reads from the Law of Moses out loud, with translators interpreting verse by verse into Aramaic (the language of the exile generation) so the people can understand. As they listen, they begin to weep. Maybe they weep because they realize how far their families have drifted. Maybe they weep with the shock of finally hearing what was always meant for them to hear.</p><p>Nehemiah, Ezra, and the Levites turn the tears around: "This day is holy to the LORD your God; do not mourn or weep... Go your way. Eat the fat and drink sweet wine and send portions to anyone who has nothing ready, for this day is holy to our Lord. And do not be grieved, for the joy of the LORD is your strength." The people throw a feast. They build temporary booths for the Feast of Tabernacles — the first such observance "since the days of Joshua." Scripture, read aloud, has set off the largest revival the post-exile community ever saw.</p>`,
    whyMatters:`<p>What revival looks like in most generations is the Book being read aloud and understood, the people weeping at what they had forgotten, and then feasting because joy follows obedience. There is nothing new under the sun. Open the book.</p>`,
    keyVerse:{ ref:'Nehemiah 8:10', text:'Do not be grieved, for the joy of the LORD is your strength.' },
    scriptureRefs:['Nehemiah 8:1-12'] },
  { id:'malachi', year:-430, displayYear:'~430 BC', era:'exile-return',
    icon:'📚', title:'Malachi · The OT Closes',
    subtitle:'400 silent years begin.',
    body:`<p>Roughly a hundred years after the return. The Temple is rebuilt. The wall is rebuilt. The Law has been read. And the people are bored. They have drifted again — bringing the lame and blind animals as offerings, divorcing their wives, withholding their tithes, intermarrying with the surrounding nations and giving their daughters to pagan worship. The priests are exhausted by their own ritual: "What a weariness this is!"</p><p>God sends Malachi — the last prophet of the Old Testament — to confront them in a series of disputations. Each follows the same pattern: God states an accusation, the people protest "How have we...?", and God answers in detail. They have despised His name. They have wearied Him with their complaints that evil is rewarded. They have robbed Him in the tithes and offerings. Yet through every confrontation runs a thread of promise. "Bring the full tithes... and thereby put me to the test, says the LORD of hosts, if I will not open the windows of heaven for you."</p><p>The book ends with two extraordinary verses. "Behold, I will send the prophet Elijah to you before the great and awesome day of the LORD comes. And he will turn the hearts of fathers to their children, and the hearts of children to their fathers." Then God closes His mouth. For four hundred years there is no prophet. No new word. The page turns silently — and then opens on the Gospel of Matthew, in the days when an angel appears to a priest named Zechariah and announces the birth of a son who will come "in the spirit and power of Elijah." Heaven was always waiting for the right baby.</p>`,
    whyMatters:`<p>God's silence is not God's absence. The four centuries between Malachi and Matthew were filling with Roman roads, Greek language, a synagogue in every town, and a longing for the Messiah. The waiting was the work.</p>`,
    keyVerse:{ ref:'Malachi 3:1', text:'Behold, I send my messenger, and he will prepare the way before me. And the Lord whom you seek will suddenly come to his temple.' },
    scriptureRefs:['Malachi 4:5-6'] },

  // ── ACT 8: SECOND TEMPLE / INTERTESTAMENTAL ───────────────
  { id:'septuagint', year:-250, displayYear:'~250 BC', era:'second-temple',
    icon:'📖', title:'The Septuagint',
    subtitle:'The Hebrew Scriptures go Greek.',
    body:`<p>The Jewish diaspora has grown. Alexander the Great's conquests have made Greek the international language of the eastern Mediterranean. Jews in Alexandria — the great cosmopolitan city in Egypt — speak Greek every day; their children no longer read Hebrew well. The Ptolemaic rulers want a copy of every important book for their famous library. According to the Letter of Aristeas, around 250 BC, seventy-two Jewish scholars (six from each tribe) are gathered to translate the Hebrew Scriptures into Greek. The number is rounded down to seventy — and the translation gets called the Septuagint, the LXX.</p><p>It is the first major translation of Scripture in history. It carries the prophets out into the Greek-speaking world. When Paul plants churches in Antioch, Corinth, Ephesus, and Rome, the Bible he reads and quotes is overwhelmingly the LXX. When Matthew writes that a virgin shall conceive (Isaiah 7:14), he is quoting the Greek word the Septuagint translators chose: parthenos. The Spirit was already setting up the Christmas story two centuries before it happened.</p><p>The LXX also bridges the Old and New Testament canons. The early church preserved it; the synagogue eventually moved away from it. But for the first Christians, including the writers of the New Testament, the Septuagint was Scripture. The Hebrew Bible going Greek was a quiet act of preparation. God was making sure the Word would reach the world He was about to step into.</p>`,
    whyMatters:`<p>God prepares the road centuries before the runner arrives. Languages translated, roads built, currencies standardized, hearts hungering — every preparation is His. Whatever ground He is preparing in your life right now, you may not see what He is preparing it for.</p>`,
    keyVerse:{ ref:'Isaiah 40:3', text:'A voice cries: In the wilderness prepare the way of the LORD; make straight in the desert a highway for our God.' },
    scriptureRefs:[] },
  { id:'maccabees', year:-165, displayYear:'~165 BC', era:'second-temple',
    icon:'⚔️', title:'The Maccabean Revolt',
    subtitle:'Faithful Jews defy Antiochus IV.',
    body:`<p>The Greek empire after Alexander has fractured. Judea is caught between the Ptolemies in Egypt and the Seleucids in Syria. Around 175 BC, a Seleucid king named Antiochus IV Epiphanes — "the manifest god" — comes to power and decides to forcibly Hellenize the Jews. He outlaws circumcision, Sabbath observance, and the food laws on pain of death. In the climactic blasphemy, he enters the Temple, sets up a statue of Zeus on the altar of burnt offering, and sacrifices a pig there. The "abomination of desolation" that Daniel had prophesied (Daniel 11:31) has arrived.</p><p>An elderly priest named Mattathias in the town of Modein refuses to offer a pagan sacrifice when the king's officials demand it. When another Jew steps up to do it, Mattathias kills him on the spot, then the king's official too, then calls out: "Let everyone who is zealous for the Law and supports the covenant come out with me!" He and his five sons flee to the hills. The revolt begins. After Mattathias's death, his son Judah — nicknamed "the Maccabee" (the Hammer) — leads. Outnumbered and outgunned, the Maccabees use guerrilla tactics, faith, and the inspired courage that comes when a people decides their soul matters more than their safety.</p><p>Three years of fighting. The Seleucid armies are humiliated repeatedly. By 164 BC, Judah retakes Jerusalem and reclaims the Temple. It is a story not told in the Christian Old Testament but preserved in 1 and 2 Maccabees. Jesus celebrates its anniversary in John 10. The Pharisees who confront Him are spiritual descendants of the Maccabean resistance. The world Jesus was born into was a world that had only recently won the right to be Jewish.</p>`,
    whyMatters:`<p>There are moments when faithfulness looks like resistance. The Maccabees did not survive by negotiating. The Spirit who steadied them is the same Spirit who is still steadying anyone whose faith costs them more than they wanted to pay.</p>`,
    keyVerse:{ ref:'Daniel 11:32', text:'The people who know their God shall stand firm and take action.' },
    scriptureRefs:[] },
  { id:'hanukkah', year:-164, displayYear:'~164 BC', era:'second-temple',
    icon:'🕎', title:'The Temple Rededicated',
    subtitle:'A festival of lights begins.',
    body:`<p>The altar is rebuilt; the menorah relit. Tradition says one day's oil burned for eight. Hanukkah remembers it every winter. Jesus Himself walks Solomon's Colonnade during this Feast of Dedication.</p>`,
    scriptureRefs:['John 10:22-23'] },
  { id:'rome-judea', year:-63, displayYear:'63 BC', era:'second-temple',
    icon:'🦅', title:'Rome Takes Judea',
    subtitle:'Pompey enters the Holy of Holies.',
    body:`<p>The Roman general Pompey besieges Jerusalem and walks straight into the Most Holy Place, finding it empty. Judea becomes a client state of Rome — setting the political stage on which Jesus will be born.</p>`,
    scriptureRefs:[] },
  { id:'herod', year:-37, displayYear:'37 BC', era:'second-temple',
    icon:'🏯', title:'Herod the Great',
    subtitle:'A paranoid king rebuilds the Temple.',
    body:`<p>An Idumean king on a Jewish throne by Roman appointment. Brilliant, paranoid, brutal. He doubles the Temple Mount and rebuilds the sanctuary on a scale to rival Solomon's. He is still on the throne when Jesus is born.</p>`,
    scriptureRefs:['Matthew 2:1-18'], relatedSiteId:'temple-mount' },

  // ── ACT 9: JESUS ──────────────────────────────────────────
  { id:'birth', year:-4, displayYear:'~5 BC', era:'jesus-ministry',
    icon:'⭐', title:'Birth of Jesus',
    subtitle:'God enters time.',
    body:`<p>The angels sing over Bethlehem. Shepherds run to a stable. The Magi follow a star and bring gold, frankincense, myrrh. "The Word became flesh and dwelt among us, and we have seen His glory."</p>`,
    scriptureRefs:['Luke 2:1-20','John 1:14'], relatedSiteId:'bethlehem' },
  { id:'john-baptist', year:27, displayYear:'~27 AD', era:'jesus-ministry',
    icon:'🐪', title:'John the Baptist',
    subtitle:'A voice crying in the wilderness.',
    body:`<p>Camel's hair, locusts, wild honey. John preaches repentance and baptizes thousands in the Jordan. He is the messenger Malachi promised — preparing the way for One whose sandals he is not worthy to untie.</p>`,
    scriptureRefs:['Matthew 3:1-12','Isaiah 40:3'], relatedSiteId:'jordan-river' },
  { id:'baptism', year:28, displayYear:'~28 AD', era:'jesus-ministry',
    icon:'🕊️', title:"Jesus's Baptism",
    subtitle:'The Father affirms before the work begins.',
    body:`<p>Jesus enters the Jordan. The heavens tear open. The Spirit descends as a dove. The Father's voice: "This is my beloved Son, with whom I am well pleased." The Trinity together at the start of the mission.</p>`,
    scriptureRefs:['Matthew 3:13-17'], relatedSiteId:'jordan-river' },
  { id:'twelve-called', year:28, displayYear:'~28 AD', era:'jesus-ministry',
    icon:'⚓', title:'Calling the Twelve',
    subtitle:'"Follow me."',
    body:`<p>Fishermen drop their nets at a word. A tax collector leaves his booth. A zealot, a doubter, a betrayer-to-come. Jesus chooses an unlikely twelve and prays all night before naming them.</p>`,
    scriptureRefs:['Mark 1:16-20','Luke 6:12-16'] },
  { id:'sermon-mount', year:29, displayYear:'~29 AD', era:'jesus-ministry',
    icon:'⛰️', title:'Sermon on the Mount',
    subtitle:"The kingdom's constitution.",
    body:`<p>"Blessed are the poor in spirit." "Love your enemies." "Seek first the kingdom of God." Three chapters that turned the world's values upside down and have never been digested since.</p>`,
    scriptureRefs:['Matthew 5-7'] },
  { id:'feeding-5000', year:29, displayYear:'~29 AD', era:'jesus-ministry',
    icon:'🍞', title:'Feeding the 5,000',
    subtitle:'Five loaves, two fish, a kingdom picnic.',
    body:`<p>A boy's lunch in His hands. He looks to heaven, blesses, breaks, hands out — and keeps handing. Twelve baskets of leftovers. The crowd wants to crown Him; He withdraws. "I am the bread of life."</p>`,
    scriptureRefs:['John 6:1-15','John 6:35'] },
  { id:'transfiguration', year:29, displayYear:'~29 AD', era:'jesus-ministry',
    icon:'✨', title:'The Transfiguration',
    subtitle:'A flash of resurrection glory.',
    body:`<p>On a high mountain, Jesus's face shines like the sun. Moses and Elijah appear talking with Him. The Father's voice again: "This is my beloved Son — listen to Him." The disciples fall on their faces.</p>`,
    scriptureRefs:['Matthew 17:1-8'] },
  { id:'lazarus', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'⚱️', title:'Lazarus Raised',
    subtitle:'"I am the resurrection and the life."',
    body:`<p>Four days in the tomb. Mary and Martha grieving. Jesus weeps with them — then shouts at the grave: "Lazarus, come out!" The dead man walks out wrapped in his graveclothes. The crowd splits; the Sanhedrin starts planning.</p>`,
    scriptureRefs:['John 11:25','John 11:43-44'] },
  { id:'triumphal-entry', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🐴', title:'Triumphal Entry',
    subtitle:'A king on a donkey.',
    body:`<p>Palm Sunday. Cloaks and palm branches on the road. "Hosanna! Blessed is He who comes in the name of the LORD!" Jesus weeps over the city that will reject Him by Friday. The lamb walks into Jerusalem for Passover.</p>`,
    scriptureRefs:['Matthew 21:1-11','Zechariah 9:9'], relatedSiteId:'jerusalem' },
  { id:'last-supper', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🍞', title:'The Last Supper',
    subtitle:'A new covenant in bread and wine.',
    body:`<p>An upper room. Feet washed by the Master's hands. "This is my body, given for you. This cup is the new covenant in my blood." Judas leaves into the night. Peter swears he will never deny.</p>`,
    scriptureRefs:['Luke 22:14-23','John 13:1-17'] },
  { id:'gethsemane', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🌿', title:'Gethsemane',
    subtitle:'"Not my will, but yours."',
    body:`<p>An olive press at the foot of the Mount of Olives. Drops of blood-sweat in the dirt. Three times He prays. "Father, if it is possible, let this cup pass." A kiss. Soldiers. The disciples scatter.</p>`,
    scriptureRefs:['Matthew 26:36-46','Luke 22:44'], relatedSiteId:'mount-of-olives' },
  { id:'crucifixion', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'✝️', title:'The Crucifixion',
    subtitle:'It is finished.',
    body:`<p>The Lamb of God takes away the sin of the world. Three hours of darkness over the land. The Temple veil tears top to bottom. "Father, into your hands I commit my spirit." Heaven's payment in full.</p>`,
    scriptureRefs:['John 19','Isaiah 53'], relatedSiteId:'garden-tomb' },
  { id:'resurrection', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'🌅', title:'The Resurrection',
    subtitle:'Death loses.',
    body:`<p>Sunday at dawn. The stone rolled away. Angels. The empty tomb. "He is not here, He is risen — just as He said." Mary first, then Peter, then five hundred at once. History's hinge swings open.</p>`,
    scriptureRefs:['Matthew 28','1 Corinthians 15:3-8'], relatedSiteId:'garden-tomb' },
  { id:'ascension', year:30, displayYear:'~30 AD', era:'jesus-ministry',
    icon:'☁️', title:'The Ascension',
    subtitle:'Jesus is enthroned.',
    body:`<p>Forty days of resurrection appearances. Then on the Mount of Olives, Jesus rises into a cloud. Two angels stand by the gaping disciples: "He will return in the same way you saw Him go."</p>`,
    scriptureRefs:['Acts 1:9-11'], relatedSiteId:'mount-of-olives' },

  // ── ACT 10: APOSTOLIC ─────────────────────────────────────
  { id:'pentecost', year:30, displayYear:'30 AD', era:'pauline-journeys',
    icon:'🔥', title:'Pentecost',
    subtitle:'The Spirit is poured out. The church is born.',
    body:`<p>A sound like a violent wind. Tongues like fire over each disciple. They speak in every language gathered for the feast. Peter preaches; three thousand believe in a single day. The mission begins.</p>`,
    scriptureRefs:['Acts 2'], relatedSiteId:'jerusalem' },
  { id:'stephen', year:34, displayYear:'~34 AD', era:'pauline-journeys',
    icon:'🪨', title:'Stephen — First Martyr',
    subtitle:'"Lord, do not hold this sin against them."',
    body:`<p>The first deacon faces the Sanhedrin with a sermon stretching from Abraham to the cross. Stones fly. A young man named Saul holds the coats. Stephen dies forgiving, "looking up to heaven" at Jesus standing to receive him.</p>`,
    scriptureRefs:['Acts 7'] },
  { id:'paul-conversion', year:34, displayYear:'~34 AD', era:'pauline-journeys',
    icon:'⚡', title:"Paul's Conversion",
    subtitle:'The persecutor becomes the apostle.',
    body:`<p>On the road to Damascus, Saul is blinded by light and meets the risen Christ: "Why do you persecute me?" Three days of darkness, then sight through Ananias's hands. The greatest theologian of the New Testament begins.</p>`,
    scriptureRefs:['Acts 9:1-22'], relatedSiteId:'damascus' },
  { id:'cornelius', year:40, displayYear:'~40 AD', era:'pauline-journeys',
    icon:'🛐', title:'Cornelius — Gospel to the Gentiles',
    subtitle:'A Roman centurion receives the Spirit.',
    body:`<p>Peter sees a vision of unclean animals — three times. He travels to Caesarea, preaches Christ to a Roman household, and the Spirit falls on them mid-sermon. The wall comes down. The mission is for everyone.</p>`,
    scriptureRefs:['Acts 10','Acts 11:18'] },
  { id:'paul-first-journey', year:46, displayYear:'~46 AD', era:'pauline-journeys',
    icon:'⛵', title:"Paul's First Journey",
    subtitle:'The gospel goes to the nations.',
    body:`<p>The Antioch church sends Paul and Barnabas to Cyprus and Asia Minor. Cities are reached, churches planted, riots survived. Jews and Gentiles, slaves and free, sit at the same Lord's Table for the first time.</p>`,
    scriptureRefs:['Acts 13','Acts 14'], relatedSiteId:'antioch' },
  { id:'jerusalem-council', year:50, displayYear:'~50 AD', era:'pauline-journeys',
    icon:'🤝', title:'The Council of Jerusalem',
    subtitle:'Gentiles enter the church without becoming Jewish.',
    body:`<p>Must Gentile believers be circumcised and keep Moses' law? The apostles, elders, and the Holy Spirit say no — grace is enough. The letter goes out to the churches. The gospel stays the gospel.</p>`,
    scriptureRefs:['Acts 15:1-29'] },
  { id:'romans-written', year:57, displayYear:'~57 AD', era:'pauline-journeys',
    icon:'📜', title:'Romans Written',
    subtitle:"The gospel's deepest exposition.",
    body:`<p>From Corinth, Paul writes to a church he hasn't yet visited. "I am not ashamed of the gospel — it is the power of God for salvation to everyone who believes." Sixteen chapters that have reshaped the world.</p>`,
    scriptureRefs:['Romans 1:16-17'], relatedSiteId:'rome' },
  { id:'paul-rome', year:60, displayYear:'~60 AD', era:'pauline-journeys',
    icon:'⚓', title:'Paul Reaches Rome',
    subtitle:'Under house arrest. Still preaching.',
    body:`<p>Storm-shipwrecked on Malta, then on to the capital of the empire. Acts ends with Paul "preaching the kingdom of God and teaching about the Lord Jesus Christ — with all boldness and without hindrance."</p>`,
    scriptureRefs:['Acts 28:30-31'], relatedSiteId:'rome' },
  { id:'james-martyred', year:62, displayYear:'~62 AD', era:'pauline-journeys',
    icon:'🕯️', title:'James of Jerusalem Martyred',
    subtitle:'The brother of Jesus dies for the Lord he once doubted.',
    body:`<p>James — head of the Jerusalem church, author of the epistle — is thrown from the Temple parapet and clubbed to death. He prays for his killers as he dies. Tradition remembers his knees calloused like a camel's from prayer.</p>`,
    scriptureRefs:['James 5:7-11'] },
  { id:'peter-paul-killed', year:67, displayYear:'~67 AD', era:'pauline-journeys',
    icon:'⚔️', title:'Peter & Paul Martyred',
    subtitle:'Two apostles, two crowns.',
    body:`<p>Under Nero's persecution: Peter crucified upside-down outside Rome, refusing to die as his Lord did; Paul beheaded outside the same walls. "I have fought the good fight, I have finished the race, I have kept the faith."</p>`,
    scriptureRefs:['2 Timothy 4:7-8'] },
  { id:'jerusalem-70', year:70, displayYear:'70 AD', era:'pauline-journeys',
    icon:'💥', title:'Jerusalem Falls Again',
    subtitle:'The Temple is destroyed. Forever.',
    body:`<p>Roman legions under Titus encircle Jerusalem. The Temple burns. Jesus had wept over this exact moment forty years earlier. The animal sacrifice ends — because the final Sacrifice has been offered.</p>`,
    scriptureRefs:['Matthew 24:2','Hebrews 10:11-14'] },
  { id:'patmos', year:95, displayYear:'~95 AD', era:'pauline-journeys',
    icon:'📖', title:'Revelation Written',
    subtitle:'John sees the end of the story.',
    body:`<p>Exiled to Patmos under Domitian, the last living apostle receives the Revelation: Christ in glory, the seven churches, the Lamb on the throne, the final victory. "Behold, I make all things new."</p>`,
    scriptureRefs:['Revelation 1:9','Revelation 21:5'], relatedSiteId:'patmos' },

  // ── ACT 11: WAITING (we are here) ─────────────────────────
  { id:'present', year:2026, displayYear:'Now', era:'present',
    icon:'⏳', title:'You Are Here',
    subtitle:'Between resurrection and return.',
    body:`<p>The story is not over. Two thousand years of waiting, growing, suffering, witnessing. The same Spirit that filled the upper room fills the church today. The same Jesus who promised to return is preparing a place.</p>`,
    scriptureRefs:['Revelation 22:20'] },
  { id:'return', year:9999, displayYear:'When?', era:'future',
    icon:'👑', title:"Christ's Return",
    subtitle:'Every knee will bow.',
    body:`<p>"In the same way you saw Him go." Every eye will see Him. Every wrong made right. The new heavens and the new earth. "He will wipe away every tear from their eyes." This is where the whole Bible has been pointing.</p>`,
    scriptureRefs:['Acts 1:11','Revelation 21:1-5','Philippians 2:10-11'] },
];

if (typeof window !== 'undefined') {
  window.BIBLE_TIMELINE_EVENTS = BIBLE_TIMELINE_EVENTS;
}
